use core::{alloc::Layout, panic::PanicInfo, ptr};

extern "C" {
    static mut sbss: u8;
    static mut ebss: u8;
}

#[no_mangle]
pub extern "C" fn rust_entry(hart_id: usize, dtb_pa: usize) -> ! {
    clear_bss();
    arch::init_early(hart_id, dtb_pa);
    rust_main(hart_id, dtb_pa)
}

fn clear_bss() {
    let start = ptr::addr_of_mut!(sbss) as usize;
    let end = ptr::addr_of_mut!(ebss) as usize;
    for addr in start..end {
        // SAFETY: The BSS section is defined by the linker script and
        // contains only zero-initialized static data. write_volatile(0)
        // on each byte is equivalent to zeroing the BSS. No other code
        // runs before clear_bss() in `rust_entry`, so there is no
        // concurrent access.
        unsafe { (addr as *mut u8).write_volatile(0) };
    }
}

fn rust_main(hart_id: usize, dtb_pa: usize) -> ! {
    mm::init();
    time::init();
    arch::init_trap_vector();
    logging::banner(hart_id, dtb_pa);
    run_early_selftest_if_requested(hart_id, dtb_pa);

    drivers::init();
    fs::mount::init_root_from_first_block_device();
    run_selftest_if_requested();
    run_user_smoke_if_requested();
    runner::run_root_scan();
    logging::shutdown_requested();
    arch::shutdown()
}

fn run_selftest_if_requested() {
    match env!("KERNEL_SELFTEST") {
        "loader" => loader::selftest::run(),
        "mm" => mm::selftest::run(),
        "net" => net::selftest::run(),
        "drivers" => drivers::selftest::run(),
        "fs" => fs::selftest::run(),
        "rootfs" => fs::selftest::run_rootfs(),
        "process" => syscall::process::selftest::run(),
        "process-ownership-red" => syscall::process::selftest::run_ownership_red(),
        "shm" => syscall::shm::selftest::run(),
        "runner" => runner::selftest::run(),
        "task" => task::selftest::run(),
        "" => {}
        other => crate::println!("unknown selftest '{}'", other),
    }
    if !env!("KERNEL_SELFTEST").is_empty() {
        logging::shutdown_requested();
        arch::shutdown();
    }
}

fn run_early_selftest_if_requested(hart_id: usize, dtb_pa: usize) {
    if env!("KERNEL_SELFTEST") == "arch" {
        arch::selftest::run(hart_id, dtb_pa);
        logging::shutdown_requested();
        arch::shutdown();
    }

    let _ = (hart_id, dtb_pa);
}

fn run_user_smoke_if_requested() {
    if env!("KERNEL_USER_SMOKE") != "1" {
        return;
    }
    let elf = include_bytes!(env!("KERNEL_USER_SMOKE_ELF"));
    crate::println!("user smoke: loading embedded ELF ({} bytes)", elf.len());
    let loaded = loader::elf::load_static_elf(elf, &["user-smoke"], &[])
        .expect("load embedded user smoke ELF");
    let token = loaded.memory.page_table().token();
    crate::println!(
        "user smoke: entry={:#x} sp={:#x} brk={:#x}",
        loaded.entry,
        loaded.stack_top,
        loaded.heap_base
    );
    syscall::process::install_current_user(syscall::process::UserTask::new(2, 1, loaded.memory));
    // SAFETY: enter_user switches to user mode with the given entry point,
    // stack pointer, and page table token. The page table has been properly
    // initialized with user mappings. The user task is installed, so traps
    // from user mode will be handled correctly. The function does not return;
    // it transfers control to user space.
    unsafe {
        arch::enter_user(loaded.entry, loaded.stack_top, token);
    }
    syscall::process::run_user_processes();
    report_user_exit();
}

pub fn report_user_exit() {
    let code = syscall::process::current_exit_code().unwrap_or(-1);
    crate::println!("kernel observed user exit status {}", code);
}

#[panic_handler]
fn panic(info: &PanicInfo<'_>) -> ! {
    logging::panic(info);
    arch::shutdown()
}

#[alloc_error_handler]
fn alloc_error(layout: Layout) -> ! {
    panic!(
        "kernel heap allocation failed: size={} align={}",
        layout.size(),
        layout.align()
    )
}

