/// Declarative macro that generates thin public-API wrappers around
/// `platform().$method()`.  Uses an optional `as $method` clause when
/// the public name differs from the trait method name.
macro_rules! delegate {
    ($vis:vis fn $name:ident($($arg:ident: $ty:ty),*) $(-> $ret:ty)?) => {
        $vis fn $name($($arg: $ty),*) $(-> $ret)? {
            platform().$name($($arg),*)
        }
    };
    ($vis:vis fn $name:ident($($arg:ident: $ty:ty),*) -> !) => {
        $vis fn $name($($arg: $ty),*) -> ! {
            platform().$name($($arg),*)
        }
    };
    ($vis:vis fn $name:ident($($arg:ident: $ty:ty),*) $(-> $ret:ty)? as $method:ident) => {
        $vis fn $name($($arg: $ty),*) $(-> $ret)? {
            platform().$method($($arg),*)
        }
    };
}

