use super::address::{PhysAddr, PhysPageNum};

pub type ArchPageTable = crate::arch::ArchPageTable;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct MapPerm {
    bits: u8,
}

impl MapPerm {
    pub const R: Self = Self { bits: 1 << 0 };
    pub const W: Self = Self { bits: 1 << 1 };
    pub const X: Self = Self { bits: 1 << 2 };
    pub const U: Self = Self { bits: 1 << 3 };
    pub const RW: Self = Self {
        bits: Self::R.bits | Self::W.bits,
    };
    pub const RX: Self = Self {
        bits: Self::R.bits | Self::X.bits,
    };
    pub const RWX: Self = Self {
        bits: Self::R.bits | Self::W.bits | Self::X.bits,
    };
    pub const USER_RW: Self = Self {
        bits: Self::R.bits | Self::W.bits | Self::U.bits,
    };
    pub const USER_RX: Self = Self {
        bits: Self::R.bits | Self::X.bits | Self::U.bits,
    };

    pub const fn empty() -> Self {
        Self { bits: 0 }
    }

    pub const fn bits(self) -> u8 {
        self.bits
    }

    pub const fn contains(self, other: Self) -> bool {
        (self.bits & other.bits) == other.bits
    }

    pub const fn union(self, other: Self) -> Self {
        Self {
            bits: self.bits | other.bits,
        }
    }

    pub const fn without(self, other: Self) -> Self {
        Self {
            bits: self.bits & !other.bits,
        }
    }

    pub const fn is_valid_leaf_perm(self) -> bool {
        (self.contains(Self::R) || self.contains(Self::X))
            && (!self.contains(Self::W) || self.contains(Self::R))
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct Translation {
    pub(crate) pa: PhysAddr,
    pub(crate) ppn: PhysPageNum,
    pub(crate) perm: MapPerm,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum PageTableError {
    OutOfMemory,
    AlreadyMapped,
    NotMapped,
    InvalidPermission,
    InvalidRange,
    Unsupported,
}

pub trait PageTableOps {
    fn new_kernel() -> Result<Self, PageTableError>
    where
        Self: Sized;
    fn map(
        &mut self,
        vpn: super::address::VirtPageNum,
        ppn: PhysPageNum,
        perm: MapPerm,
    ) -> Result<(), PageTableError>;
    fn unmap(&mut self, vpn: super::address::VirtPageNum) -> Result<(), PageTableError>;
    fn protect(
        &mut self,
        vpn: super::address::VirtPageNum,
        perm: MapPerm,
    ) -> Result<(), PageTableError>;
    fn translate(&self, va: super::address::VirtAddr) -> Option<Translation>;
    fn translate_page(&self, vpn: super::address::VirtPageNum) -> Option<(PhysPageNum, MapPerm)>;
    fn token(&self) -> usize;
    // SAFETY: Activating a page table writes to the architecture's page
    // table base register (satp on RISC-V, CSR 0x19/0x1a on LoongArch).
    // The caller must ensure the page table is valid and all referenced
    // frames remain alive for the duration of activation.
    unsafe fn activate(&self);
    fn flush_vpn(vpn: super::address::VirtPageNum);
    fn flush_all();
    fn supports_vpn(vpn: super::address::VirtPageNum) -> bool;
}

impl PageTableOps for ArchPageTable {
    fn new_kernel() -> Result<Self, PageTableError> {
        ArchPageTable::new_kernel()
    }

    fn map(
        &mut self,
        vpn: super::address::VirtPageNum,
        ppn: PhysPageNum,
        perm: MapPerm,
    ) -> Result<(), PageTableError> {
        ArchPageTable::map(self, vpn, ppn, perm)
    }

    fn unmap(&mut self, vpn: super::address::VirtPageNum) -> Result<(), PageTableError> {
        ArchPageTable::unmap(self, vpn)
    }

    fn protect(
        &mut self,
        vpn: super::address::VirtPageNum,
        perm: MapPerm,
    ) -> Result<(), PageTableError> {
        ArchPageTable::protect(self, vpn, perm)
    }

    fn translate(&self, va: super::address::VirtAddr) -> Option<Translation> {
        ArchPageTable::translate(self, va)
    }

