static FRAME_ALLOCATOR: LockedFrameAllocator = LockedFrameAllocator::new();

struct LockedFrameAllocator(UnsafeCell<FrameAllocator>);

// SAFETY: LockedFrameAllocator provides mutual exclusion through a global
// lock (the frame allocator is accessed only from non-preemptible kernel
// context on a single hart). The UnsafeCell gives interior mutability,
// but the with() method ensures exclusive access.
unsafe impl Sync for LockedFrameAllocator {}

impl LockedFrameAllocator {
    const fn new() -> Self {
        Self(UnsafeCell::new(FrameAllocator::empty()))
    }

    fn with<R>(&self, f: impl FnOnce(&mut FrameAllocator) -> R) -> R {
        // SAFETY: The kernel is single-hart and non-preemptible during
        // frame allocation. No other thread can concurrently call with(),
        // so the mutable reference is effectively exclusive.
        let allocator = unsafe { &mut *self.0.get() };
        f(allocator)
    }
}

pub fn init_from_kernel_end() {
    let kernel_end = ptr::addr_of!(ekernel) as usize;
    init(kernel_end, arch::physical_memory_region().end);
}

pub fn init(kernel_end: usize, memory_end: usize) {
    let Some(start_addr) = checked_align_up(kernel_end, PAGE_SIZE) else {
        FRAME_ALLOCATOR.with(|allocator| allocator.init(PhysPageNum(0), PhysPageNum(0)));
        return;
    };
    let start = PhysAddr(start_addr).ceil();
    let end = PhysAddr(memory_end).floor();
    FRAME_ALLOCATOR.with(|allocator| allocator.init(start, end));
}

pub fn alloc_frame() -> Option<FrameTracker> {
    FRAME_ALLOCATOR.with(|allocator| allocator.alloc().map(FrameTracker::new))
}

pub fn share_frame(ppn: PhysPageNum) -> Option<FrameTracker> {
    FRAME_ALLOCATOR.with(|allocator| {
        if allocator.retain(ppn) {
            Some(FrameTracker::from_shared(ppn))
        } else {
            None
        }
    })
}

fn release_frame(ppn: PhysPageNum) {
    assert!(
        FRAME_ALLOCATOR.with(|allocator| allocator.release(ppn)),
        "invalid frame release ppn={}",
        ppn.0
    );
}

pub fn remaining_frames() -> usize {
    FRAME_ALLOCATOR.with(|allocator| allocator.remaining())
}

pub fn total_frames() -> usize {
    FRAME_ALLOCATOR.with(|allocator| allocator.total())
}

pub struct FrameTracker {
    ppn: PhysPageNum,
}

impl FrameTracker {
    fn new(ppn: PhysPageNum) -> Self {
        // SAFETY: phys_to_virt returns a kernel-accessible virtual address
        // for the given physical page. The frame is freshly allocated and
        // exclusively owned — no other reference exists to this physical
        // memory. write_bytes zeroes a full PAGE_SIZE which is guaranteed
        // to be valid (the frame was allocated from the physical memory region).
        unsafe {
            ptr::write_bytes(
                arch::phys_to_virt(ppn.addr().as_usize()) as *mut u8,
                0,
                PAGE_SIZE,
            );
        }
        Self { ppn }
    }

    fn from_shared(ppn: PhysPageNum) -> Self {
        Self { ppn }
    }

    pub fn ppn(&self) -> PhysPageNum {
        self.ppn
    }

    pub fn ref_count(&self) -> usize {
        FRAME_ALLOCATOR.with(|allocator| allocator.ref_count(self.ppn))
    }
}

impl Clone for FrameTracker {
    fn clone(&self) -> Self {
        share_frame(self.ppn).unwrap_or_else(|| {
            panic!(
                "FrameTracker::clone: frame PPN={:#x} already released or shared",
                self.ppn.0
            )
        })
    }
}

impl Drop for FrameTracker {
    fn drop(&mut self) {
        release_frame(self.ppn);
    }
}

struct FrameAllocator {
    start: PhysPageNum,
    current: PhysPageNum,
    end: PhysPageNum,
    recycled_head: Option<PhysPageNum>,
    recycled_count: usize,
    ref_counts: Vec<usize>,
}

impl FrameAllocator {
    const fn empty() -> Self {
        Self {
            start: PhysPageNum(0),
            current: PhysPageNum(0),
            end: PhysPageNum(0),
            recycled_head: None,
            recycled_count: 0,
            ref_counts: Vec::new(),
        }
    }

    fn init(&mut self, start: PhysPageNum, end: PhysPageNum) {
        self.start = start;
        self.current = start;
        self.end = end;
        self.recycled_head = None;
        self.recycled_count = 0;
        self.ref_counts.clear();
        self.ref_counts.resize(end.0.saturating_sub(start.0), 0);
    }

    fn alloc(&mut self) -> Option<PhysPageNum> {
        if let Some(ppn) = self.recycled_head {
            // SAFETY: The freed frame stores a singly-linked list pointer
            // in its first usize. phys_to_virt converts the physical address
            // to a kernel-accessible virtual address. The frame is in the
            // recycled list and exclusively owned by the allocator;
            // no other reference exists. This is a standard buddy-allocator
            // pattern where freed memory stores bookkeeping data.
            let next = unsafe { *(arch::phys_to_virt(ppn.addr().as_usize()) as *const usize) };
            self.recycled_head = if next == 0 {
                None
            } else {
                Some(PhysPageNum(next))
            };
            self.recycled_count -= 1;
            self.set_ref_count(ppn, 1);
            return Some(ppn);
        }

        if self.current < self.end {
            let ppn = self.current;
            self.current.0 += 1;
            self.set_ref_count(ppn, 1);
            Some(ppn)
        } else {
            None
        }
    }

    fn retain(&mut self, ppn: PhysPageNum) -> bool {
        let Some(index) = self.ref_count_index(ppn) else {
            return false;
        };
        if self.ref_counts[index] == 0 {
            return false;
        }
        self.ref_counts[index] += 1;
        true
    }

    fn release(&mut self, ppn: PhysPageNum) -> bool {
        let Some(index) = self.ref_count_index(ppn) else {
            return false;
        };
        match self.ref_counts[index] {
            0 => false,
            1 => {
                self.ref_counts[index] = 0;
                self.dealloc(ppn);
                true
            }
            count => {
                self.ref_counts[index] = count - 1;
                true
            }
        }
    }

    fn ref_count(&self, ppn: PhysPageNum) -> usize {
        self.ref_count_index(ppn)
            .map(|index| self.ref_counts[index])
            .unwrap_or(0)
    }

    fn set_ref_count(&mut self, ppn: PhysPageNum, count: usize) {
        if let Some(index) = self.ref_count_index(ppn) {
            self.ref_counts[index] = count;
        }
    }

    fn ref_count_index(&self, ppn: PhysPageNum) -> Option<usize> {
        let index = ppn.0.checked_sub(self.start.0)?;
        (index < self.ref_counts.len()).then_some(index)
    }

    fn dealloc(&mut self, ppn: PhysPageNum) {
        let next = self.recycled_head.map(|head| head.0).unwrap_or(0);
        // SAFETY: The frame being deallocated has been released (ref count
        // reached zero). phys_to_virt gives a kernel-accessible virtual
        // address. We write the next-pointer value into the first usize
        // of the frame, which is safe because the frame's previous data
        // has been dropped and no other reference exists.
        unsafe {
            *(arch::phys_to_virt(ppn.addr().as_usize()) as *mut usize) = next;
        }
        self.recycled_head = Some(ppn);
        self.recycled_count += 1;
    }

    fn remaining(&self) -> usize {
        self.end.0.saturating_sub(self.current.0) + self.recycled_count
    }

    fn total(&self) -> usize {
        self.end.0.saturating_sub(self.start.0)
    }
}

