pub type KernelTaskEntry = fn(&mut Process) -> TaskAction;

const KERNEL_STACK_SIZE: usize = 16 * 1024;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum TaskAction {
    Yield,
    Exit(i32),
    Block,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum TaskState {
    Ready,
    Running,
    Blocked,
    Zombie,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum MemorySetSlot {
    Kernel,
    UserNotLoaded,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum FdTableSlot {
    KernelOnly,
    UserNotLoaded,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct FdTable {
    slot: FdTableSlot,
}

impl FdTable {
    pub const fn kernel_only() -> Self {
        Self {
            slot: FdTableSlot::KernelOnly,
        }
    }

    pub const fn slot(self) -> FdTableSlot {
        self.slot
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct ProcessResources {
    pub(crate) cwd: &'static str,
    pub(crate) root: &'static str,
    pub(crate) fd_table: FdTable,
    pub(crate) memory_set: MemorySetSlot,
}

impl ProcessResources {
    pub const fn kernel() -> Self {
        Self {
            cwd: "/",
            root: "/",
            fd_table: FdTable::kernel_only(),
            memory_set: MemorySetSlot::Kernel,
        }
    }
}

pub struct Process {
    pid: Pid,
    tgid: Pid,
    parent: Option<Pid>,
    children: Vec<Pid>,
    state: TaskState,
    exit_code: Option<i32>,
    context: TaskContext,
    kernel_stack: Option<Box<[u8; KERNEL_STACK_SIZE]>>,
    resources: ProcessResources,
    kernel_name: &'static str,
    kernel_entry: Option<KernelTaskEntry>,
    kernel_runs: usize,
    kernel_yields: usize,
}

impl Process {
    pub fn new_root(pid: Pid, name: &'static str) -> Self {
        Self {
            pid,
            tgid: pid,
            parent: None,
            children: Vec::new(),
            state: TaskState::Running,
            exit_code: None,
            context: TaskContext::zeroed(),
            kernel_stack: None,
            resources: ProcessResources::kernel(),
            kernel_name: name,
            kernel_entry: None,
            kernel_runs: 0,
            kernel_yields: 0,
        }
    }

    pub fn new_kernel(pid: Pid, parent: Pid, name: &'static str, entry: KernelTaskEntry) -> Self {
        let kernel_stack = Box::new([0; KERNEL_STACK_SIZE]);
        let stack_top = kernel_stack.as_ptr() as usize + KERNEL_STACK_SIZE;
        Self {
            pid,
            tgid: pid,
            parent: Some(parent),
            children: Vec::new(),
            state: TaskState::Ready,
            exit_code: None,
            context: TaskContext::new_kernel(entry as usize, stack_top),
            kernel_stack: Some(kernel_stack),
            resources: ProcessResources::kernel(),
            kernel_name: name,
            kernel_entry: Some(entry),
            kernel_runs: 0,
            kernel_yields: 0,
        }
    }

    pub fn pid(&self) -> Pid {
        self.pid
    }

    pub fn tgid(&self) -> Pid {
        self.tgid
    }

    pub fn parent(&self) -> Option<Pid> {
        self.parent
    }

    pub fn children(&self) -> &[Pid] {
        &self.children
    }

    pub fn state(&self) -> TaskState {
        self.state
    }

    pub fn exit_code(&self) -> Option<i32> {
        self.exit_code
    }

    pub fn context(&self) -> &TaskContext {
        &self.context
    }

    pub fn kernel_stack_top(&self) -> usize {
        self.kernel_stack
            .as_ref()
            .map(|stack| stack.as_ptr() as usize + KERNEL_STACK_SIZE)
            .unwrap_or(0)
    }

    pub fn resources(&self) -> ProcessResources {
        self.resources
    }

    pub fn kernel_name(&self) -> &'static str {
        self.kernel_name
    }

    pub fn kernel_runs(&self) -> usize {
        self.kernel_runs
    }

    pub fn kernel_yields(&self) -> usize {
        self.kernel_yields
    }

    pub fn add_child(&mut self, pid: Pid) {
        self.children.push(pid);
    }

    pub fn remove_child(&mut self, pid: Pid) -> bool {
        if let Some(index) = self.children.iter().position(|child| *child == pid) {
            self.children.remove(index);
            true
        } else {
            false
        }
    }

    pub fn mark_ready(&mut self) {
        self.state = TaskState::Ready;
    }

    pub fn mark_running(&mut self) {
        self.state = TaskState::Running;
    }

    pub fn mark_blocked(&mut self) {
        self.state = TaskState::Blocked;
    }

    pub fn mark_zombie(&mut self, exit_code: i32) {
        self.state = TaskState::Zombie;
        self.exit_code = Some(exit_code);
    }

    pub fn record_yield(&mut self) {
        self.kernel_yields += 1;
    }

    pub fn run_kernel_step(&mut self) -> TaskAction {
        self.kernel_runs += 1;
        match self.kernel_entry {
            Some(entry) => entry(self),
            None => TaskAction::Exit(0),
        }
    }
}

