const SSTATUS_SPP: usize = 1 << 8;
const SSTATUS_SPIE: usize = 1 << 5;
const SCAUSE_INTERRUPT: usize = 1usize << (usize::BITS - 1);
const SCAUSE_SUPERVISOR_TIMER: usize = SCAUSE_INTERRUPT | 5;
const SIE_STIE: usize = 1 << 5;
const TIMER_PREEMPT_SAME_PC_TICKS: usize = 10;

static LAST_TRAP_SEPC: AtomicUsize = AtomicUsize::new(0);
static LAST_TRAP_SSTATUS: AtomicUsize = AtomicUsize::new(0);
static LAST_TIMER_USER_PC: AtomicUsize = AtomicUsize::new(0);
static SAME_TIMER_PC_TICKS: AtomicUsize = AtomicUsize::new(0);

extern "C" {
    fn __riscv64_trap_entry();
    fn __riscv64_enter_user(entry: usize, stack_top: usize, satp: usize);
    fn __riscv64_enter_user_frame(frame: *const TrapFrame, satp: usize);
    static __riscv64_trap_stack_top: u8;
}

#[repr(C)]
#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(crate) struct TrapFrame {
    pub(crate) regs: [usize; 32],
    pub(crate) sstatus: usize,
    pub(crate) sepc: usize,
    pub(crate) fp_regs: [u64; 32],
    pub(crate) fcsr: usize,
}

// SAFETY: TrapFrame is a plain data structure (repr(C), all fields are
// primitive integers). It contains no pointers, no resource handles, and
// no internal invariants that would be violated by cross-thread send.
unsafe impl Send for TrapFrame {}
// SAFETY: TrapFrame contains no interior mutability (all fields are plain
// data). Shared references to TrapFrame cannot be used to mutate it, so
// sharing across threads is sound.
unsafe impl Sync for TrapFrame {}

impl Default for TrapFrame {
    fn default() -> Self {
        Self {
            regs: [0; 32],
            sstatus: 0,
            sepc: 0,
            fp_regs: [0; 32],
            fcsr: 0,
        }
    }
}

impl TrapFrame {
    pub const SYSCALL_ID_REG: usize = 17;
    pub const SYSCALL_ARG_BASE: usize = 10;
    pub const SYSCALL_RET_REG: usize = 10;
    pub const STACK_POINTER_REG: usize = 2;
    pub const THREAD_POINTER_REG: usize = 4;

    pub fn syscall_id(&self) -> usize {
        self.regs[Self::SYSCALL_ID_REG]
    }

    pub fn set_syscall_id(&mut self, id: usize) {
        self.regs[Self::SYSCALL_ID_REG] = id;
    }

    pub fn syscall_arg(&self, index: usize) -> Option<usize> {
        if index < 6 {
            Some(self.regs[Self::SYSCALL_ARG_BASE + index])
        } else {
            None
        }
    }

    pub fn set_syscall_arg(&mut self, index: usize, value: usize) {
        assert!(index < 6);
        self.regs[Self::SYSCALL_ARG_BASE + index] = value;
    }

    pub fn syscall_args(&self) -> [usize; 6] {
        [
            self.regs[10],
            self.regs[11],
            self.regs[12],
            self.regs[13],
            self.regs[14],
            self.regs[15],
        ]
    }

    pub fn syscall_return(&self) -> usize {
        self.regs[Self::SYSCALL_RET_REG]
    }

    pub fn set_syscall_return(&mut self, value: usize) {
        self.regs[Self::SYSCALL_RET_REG] = value;
    }

    pub fn set_user_stack_pointer(&mut self, stack: usize) {
        self.regs[Self::STACK_POINTER_REG] = stack;
    }

    pub fn prepare_user_return(&mut self) {
        self.sstatus &= !SSTATUS_SPP;
        self.sstatus |= SSTATUS_SPIE;
    }

    pub fn advance_sepc(&mut self) {
        self.sepc = self.sepc.wrapping_add(4);
    }

    pub fn retreat_sepc(&mut self) {
        self.sepc = self.sepc.wrapping_sub(4);
    }
}

pub fn init_trap_vector() {
    let entry = __riscv64_trap_entry as usize;
    let stack_top = core::ptr::addr_of!(__riscv64_trap_stack_top) as usize;
    // SAFETY: Writing to sscratch and stvec CSRs is architecture-defined
    // and required for trap handling setup. sscratch holds the trap stack
    // pointer for use by the trap entry assembly. stvec holds the trap
    // handler address, which is 4-byte aligned (DIRECT mode). These CSRs
    // have no side effects on memory or other state.
    unsafe {
        core::arch::asm!("csrw sscratch, {}", in(reg) stack_top, options(nomem, nostack, preserves_flags));
        core::arch::asm!("csrw stvec, {}", in(reg) entry, options(nomem, nostack, preserves_flags));
    }
}

pub fn enable_timer_interrupt() {
    // SAFETY: Setting the STIE (Supervisor Timer Interrupt Enable) bit in
    // the sie CSR enables timer interrupts in supervisor mode. This is a
    // standard RISC-V CSR operation with no side effects on memory.
    unsafe {
        core::arch::asm!(
            "csrs sie, {}",
            in(reg) SIE_STIE,
            options(nomem, nostack, preserves_flags)
        );
    }
}

pub fn last_trap() -> (usize, usize) {
    (
        LAST_TRAP_SEPC.load(Ordering::Relaxed),
        LAST_TRAP_SSTATUS.load(Ordering::Relaxed),
    )
}

pub unsafe fn enter_user(entry: usize, stack_top: usize, satp: usize) {
    __riscv64_enter_user(entry, stack_top, satp)
}

pub unsafe fn enter_user_frame(frame: &TrapFrame, satp: usize) {
    __riscv64_enter_user_frame(frame as *const TrapFrame, satp)
}

pub unsafe fn clear_user_address_space() {
    core::arch::asm!(
        "csrw satp, zero",
        "sfence.vma",
        options(nostack, preserves_flags)
    );
}

