pub extern "C" fn riscv64_trap_handler(frame: &mut TrapFrame) -> usize {
    let scause = read_scause();
    let stval = read_stval();
    let from_user = frame.sstatus & SSTATUS_SPP == 0;
    if from_user {
        frame.prepare_user_return();
    }
    LAST_TRAP_SEPC.store(frame.sepc, Ordering::Relaxed);
    LAST_TRAP_SSTATUS.store(frame.sstatus, Ordering::Relaxed);

    if !from_user {
        return 0;
    }

    match scause {
        8 => handle_user_syscall(frame),
        SCAUSE_SUPERVISOR_TIMER => handle_user_timer_interrupt(frame),
        15 => {
            if crate::syscall::process::handle_user_write_page_fault(stval)
                || crate::syscall::process::handle_user_page_fault(stval)
                || crate::syscall::process::deliver_current_sync_signal_handler(
                    frame,
                    crate::syscall::process::SIGSEGV,
