                || crate::syscall::process::deliver_current_sync_signal_handler(
                    frame,
                    crate::syscall::process::SIGSEGV,
                )
            {
                0
            } else {
                terminate_user_trap(scause, frame.sepc, stval)
            }
        }
        _ if scause & SCAUSE_INTERRUPT != 0 => 0,
        _ => terminate_user_trap(scause, frame.sepc, stval),
    }
}

fn handle_user_timer_interrupt(frame: &mut TrapFrame) -> usize {
    crate::arch::riscv64::set_next_timer_interrupt();
    let delivered =
        crate::syscall::process::handle_user_timer_interrupt(frame, crate::arch::uptime_micros());
