        1
    } else {
        0
    }
}

pub(crate) fn should_schedule_after_user_timer_interrupt(user_pc: usize) -> bool {
    if !crate::syscall::process::has_other_runnable_user() {
        return false;
    }
    let last = LAST_TIMER_USER_PC.swap(user_pc, Ordering::Relaxed);
