fn read_scause() -> usize {
    let value: usize;
    // SAFETY: Reading the scause CSR returns the supervisor trap cause.
    // This is a read-only CSR with no side effects on memory. The
    // nomem/nostack options correctly describe the asm constraints.
    unsafe {
        core::arch::asm!("csrr {}, scause", out(reg) value, options(nomem, nostack, preserves_flags))
    };
    value
}

fn read_time() -> u64 {
    let value: u64;
    // SAFETY: The RISC-V `rdtime` pseudo-instruction reads the mtime CSR,
    // which is the machine-level timer counter. It has no side effects on
    // memory and is always readable in supervisor mode (S-mode has read-only
    // access to time CSRs through the Sstc extension or OpenSBI emulation).
    unsafe {
        core::arch::asm!("rdtime {}", out(reg) value, options(nomem, nostack, preserves_flags))
    };
    value
}

fn read_sepc() -> usize {
    let value: usize;
    // SAFETY: Reading the sepc CSR returns the supervisor exception program
    // counter. Used only for panic diagnostics. Read-only CSR, no side effects.
    unsafe {
        core::arch::asm!("csrr {}, sepc", out(reg) value, options(nomem, nostack, preserves_flags))
    };
    value
}

fn read_stval() -> usize {
    let value: usize;
    // SAFETY: Reading the stval CSR returns additional trap information.
    // Used only for panic diagnostics. Read-only CSR, no side effects.
    unsafe {
        core::arch::asm!("csrr {}, stval", out(reg) value, options(nomem, nostack, preserves_flags))
    };
    value
}

