        let pid = self.pid();
        while let Some(signum) = self.table.take_signal_wake(pid) {
            if signal_wake_interrupts_blocking_syscall(&self.table.tasks[self.index], signum) {
                return true;
            }
        }
        self.table
            .take_wake_reason(pid, crate::task::wait_queue::WakeReason::SignalPending)
    }

