            .map_err(|_| ())?;
        if self.current_memory_covers_live_thread_stacks(tgid) {
            return Ok(candidate);
        }
        loop {
            let mut next_minimum = None;
            for &index in self.table.thread_indices_for_tgid(tgid) {
                let task = &self.table.tasks[index];
                if index == self.index || task.tgid != tgid || task.state == UserTaskState::Zombie {
                    continue;
                }
                let Some(overlap_end) = task
                    .memory
                    .first_user_metadata_overlap_end(candidate, len)
                    .map_err(|_| ())?
                else {
