const CLONE_SIGNAL_MASK: usize = 0xff;
const CLONE_VM: usize = 0x0000_0100;
const CLONE_FS: usize = 0x0000_0200;
const CLONE_FILES: usize = 0x0000_0400;
const CLONE_SIGHAND: usize = 0x0000_0800;
const CLONE_VFORK: usize = 0x0000_4000;
const CLONE_THREAD: usize = 0x0001_0000;
const CLONE_SYSVSEM: usize = 0x0004_0000;
const CLONE_SETTLS: usize = 0x0008_0000;
const CLONE_PARENT_SETTID: usize = 0x0010_0000;
const CLONE_CHILD_CLEARTID: usize = 0x0020_0000;
const CLONE_DETACHED: usize = 0x0040_0000;
const CLONE_CHILD_SETTID: usize = 0x0100_0000;
const CLONE_SUPPORTED_FLAGS: usize = CLONE_SIGNAL_MASK
    | CLONE_VM
    | CLONE_FS
    | CLONE_FILES
    | CLONE_SIGHAND
    | CLONE_VFORK
    | CLONE_THREAD
    | CLONE_SYSVSEM
    | CLONE_SETTLS
    | CLONE_PARENT_SETTID
    | CLONE_CHILD_CLEARTID
    | CLONE_DETACHED
    | CLONE_CHILD_SETTID;
pub fn sys_clone(
    frame: &UserTrapFrame,
    flags: usize,
    stack: usize,
    ptid: usize,
    tls: usize,
    ctid: usize,
) -> SyscallRet {
    if flags & !CLONE_SUPPORTED_FLAGS != 0 {
        return err(EINVAL);
    }
    let exit_signal = flags & CLONE_SIGNAL_MASK;
    let thread_like = flags & CLONE_THREAD != 0;
    let vfork_like = flags & (CLONE_VM | CLONE_VFORK) == (CLONE_VM | CLONE_VFORK);
    if thread_like {
        if exit_signal != 0
            || flags & CLONE_VM == 0
            || flags & CLONE_SIGHAND == 0
            || flags & CLONE_FILES == 0
        {
            return err(EINVAL);
        }
    } else if exit_signal != SIGCHLD
        || flags & (CLONE_THREAD | CLONE_SETTLS) != 0
        || (flags & CLONE_VM != 0 && !vfork_like)
        || (flags & CLONE_VFORK != 0 && !vfork_like)
    {
        return err(EINVAL);
    }

    let mut table = USER_PROCESSES.lock();
    super::super::table::reap_before_clone_locked(&mut table);
    let Some(parent_index) = table.current_index() else {
        return err(EPERM);
    };
    if table.tasks[parent_index].state != UserTaskState::Running {
        return err(EPERM);
    }

    let pid = table.allocate_pid();
    let parent_pid = table.tasks[parent_index].pid;
    let mut child_frame = *frame;
    child_frame.set_return_value(0);
    if stack != 0 {
        child_frame.set_user_sp(stack);
    }
    if flags & CLONE_SETTLS != 0 {
        child_frame.set_user_tls(tls);
    }

    let memory = if thread_like {
        trace_thread_clone_pressure("before", &table, parent_index, pid);
        Arc::clone(&table.tasks[parent_index].memory)
    } else {
        match table.tasks[parent_index].memory.try_clone_user() {
            Ok(memory) => Arc::new(AddressSpace::new(memory)),
            Err(_) => return err(EFAULT),
        }
    };
    let signal_actions = {
        let parent = &table.tasks[parent_index];
        if thread_like {
            parent.signal_actions.shared_clone()
        } else {
            parent.signal_actions.fork_copy()
        }
    };
    let mut child = UserTask::new_with_address_space(pid, parent_pid, memory, signal_actions);
    child.tgid = if thread_like {
        table.tasks[parent_index].tgid
    } else {
        pid
    };
    if thread_like {
        child.thread_user_stack = child_frame.user_sp();
    }
    if flags & CLONE_PARENT_SETTID != 0 {
        let bytes = pid.to_ne_bytes();
        if table.tasks[parent_index]
            .memory
            .write_user_bytes(ptid, &bytes)
            .is_err()
        {
            return err(EFAULT);
        }
    }
    if flags & CLONE_CHILD_SETTID != 0 {
        if child
            .memory
            .write_user_bytes(ctid, &pid.to_ne_bytes())
            .is_err()
        {
            return err(EFAULT);
        }
        if thread_like
            && table.tasks[parent_index]
                .memory
                .write_user_bytes(ctid, &pid.to_ne_bytes())
                .is_err()
        {
            return err(EFAULT);
        }
    }
    if flags & CLONE_CHILD_CLEARTID != 0 {
        child.clear_child_tid = ctid;
    }
    if thread_like && flags & CLONE_SETTLS != 0 && ptid != 0 && tls != 0 {
        let pthread_base = ptid.saturating_sub(super::super::table::MUSL_PTHREAD_TID_OFFSET);
        if tls.saturating_sub(pthread_base) == super::super::table::MUSL_PTHREAD_TLS_OFFSET {
            child.pthread_base = pthread_base;
        }
    }
    {
        let parent = &table.tasks[parent_index];
        child.cwd = parent.cwd.clone();
        child.exec_variant_root = parent.exec_variant_root;
        child.exec_inode = parent.exec_inode;
        child.fd_table = if flags & CLONE_FILES != 0 {
            parent.fd_table.shared_clone()
        } else {
            parent.fd_table.fork_copy()
        };
        child.signal_mask = parent.signal_mask;
        child.resource_limits = parent.resource_limits;
        child.personality = parent.personality;
        child.pgid = parent.pgid;
        child.sid = parent.sid;
        child.credentials = parent.credentials;
        child.sched_policy = parent.sched_policy;
        child.sched_priority = parent.sched_priority;
    }
    child.state = UserTaskState::Ready;
    child.trap_frame = Some(child_frame);
    table.push_task(child);
    if thread_like {
        let child_index = table.tasks.len() - 1;
        trace_thread_clone_pressure("after", &table, child_index, pid);
    }
    if thread_like {
        super::super::table::trace_thread_clone_locked("after-clone", &table, pid, ptid, tls, ctid);
        trace_la_shared_words_locked("after-clone", &table, ctid);
    }
    pid as isize
}

