const FS_IOC_GETFLAGS: u32 = 0x8008_6601;
const FS_IOC_SETFLAGS: u32 = 0x4008_6602;
const FS_IOC_FLAGS_LEN: usize = core::mem::size_of::<i32>();

pub enum OpenFileKind {
    Inode(OpenFile),
    Console,
    Stdin,
    Pipe(pipe::PipeEndpoint),
    Socket(socket::SocketEndpoint),
}

pub struct OpenFile {
    pub(crate) inode: NodeId,
    pub(crate) file_type: FileType,
    pub(crate) offset: u64,
    access: FileAccess,
    ops: Arc<dyn FileOps>,
    dentry: Option<DentryObject>,
    path_len: usize,
    path: [u8; path::MAX_PATH],
}

impl OpenFile {
    pub fn new(inode: NodeId, file_type: FileType, path: &str) -> Self {
        Self::new_with_ops(inode, file_type, path, file_ops_for_node(inode))
    }

    pub fn new_with_ops(
        inode: NodeId,
        file_type: FileType,
        path: &str,
        ops: Arc<dyn FileOps>,
    ) -> Self {
        let mut stored = [0u8; path::MAX_PATH];
        let len = core::cmp::min(path.len(), stored.len());
        stored[..len].copy_from_slice(&path.as_bytes()[..len]);
        let file = Self {
            inode,
            file_type,
            offset: 0,
            access: FileAccess::READ_WRITE,
            ops,
            dentry: None,
            path_len: len,
            path: stored,
        };
        file.retain_ramfs_inode();
        file
    }

    pub(super) fn with_dentry_object(mut self, dentry: DentryObject) -> Self {
        self.dentry = Some(dentry);
        self
    }

    pub fn file_ops(&self) -> &dyn FileOps {
        self.ops.as_ref()
    }

    pub fn file_ops_refcount(&self) -> usize {
        Arc::strong_count(&self.ops)
    }

    pub fn path(&self) -> &str {
        core::str::from_utf8(&self.path[..self.path_len]).unwrap_or("/")
    }

    pub fn inode_object(&self) -> Result<InodeObject, isize> {
        inode_object_for_node(self.inode)
    }

    pub fn dentry_object(&self) -> Result<DentryObject, isize> {
        if let Some(dentry) = &self.dentry {
            dentry_cache().insert_object(dentry.clone());
            return Ok(dentry.clone());
        }
        path_lookup().lookup_object(self.path())
    }

    pub fn set_access(&mut self, access: FileAccess) {
        self.access = access;
    }

    pub fn can_read(&self) -> bool {
        self.access.can_read()
    }

    pub fn can_write(&self) -> bool {
        self.access.can_write()
    }

    pub fn read(&mut self, out: &mut [u8]) -> Result<usize, isize> {
        self.with_file_ops(|ops, file| ops.read(file, out))
    }

    pub fn write(&mut self, input: &[u8]) -> Result<usize, isize> {
        self.write_with_flags(input, 0)
    }

    pub fn write_with_flags(&mut self, input: &[u8], status_flags: i32) -> Result<usize, isize> {
        let result = self.with_file_ops(|ops, file| ops.write(file, input, status_flags));
        if result.is_ok() {
            invalidate_inode_after_write(self.inode);
        }
        result
    }

    pub fn getdents(&mut self, out: &mut [u8]) -> Result<usize, isize> {
        self.with_file_ops(|ops, file| ops.getdents(file, out))
    }

    pub fn stat(&self) -> Result<Metadata, isize> {
        self.file_ops().stat(self)
    }

    pub fn seek(&mut self, offset: isize, whence: SeekWhence) -> Result<u64, isize> {
        self.with_file_ops(|ops, file| ops.seek(file, offset, whence))
    }

    pub fn ioctl(&mut self, request: u32, out: &mut [u8]) -> Result<usize, isize> {
        match request {
            FS_IOC_GETFLAGS => {
                if out.len() < FS_IOC_FLAGS_LEN {
                    return Err(crate::error::EINVAL);
                }
                let flags = self.inode_object()?.file_flags()? as u32;
                out[..FS_IOC_FLAGS_LEN].copy_from_slice(&flags.to_ne_bytes());
                return Ok(FS_IOC_FLAGS_LEN);
            }
            FS_IOC_SETFLAGS => {
                if out.len() < FS_IOC_FLAGS_LEN {
                    return Err(crate::error::EINVAL);
                }
                let flags = u32::from_ne_bytes(out[..FS_IOC_FLAGS_LEN].try_into().unwrap()) as u64;
                self.inode_object()?.set_file_flags(flags)?;
                return Ok(0);
            }
            _ => {}
        }
        self.with_file_ops(|ops, file| ops.ioctl(file, request, out))
    }

    pub fn poll_revents(&self, events: i16) -> i16 {
        self.file_ops().poll_revents(self, events)
    }

    fn with_file_ops<R>(
        &mut self,
        f: impl FnOnce(&dyn FileOps, &mut OpenFile) -> Result<R, isize>,
    ) -> Result<R, isize> {
        let ops = self.ops.clone();
        f(ops.as_ref(), self)
    }

    fn retain_ramfs_inode(&self) {
        if self.inode.backend() == NodeBackend::Ramfs {
            ramfs::retain_open(self.inode.raw());
        }
    }

    fn release_ramfs_inode(&self) {
        if self.inode.backend() == NodeBackend::Ramfs {
            ramfs::release_open(self.inode.raw());
        }
    }
}

impl Clone for OpenFile {
    fn clone(&self) -> Self {
        let cloned = Self {
            inode: self.inode,
            file_type: self.file_type,
            offset: self.offset,
            access: self.access,
            ops: self.ops.clone(),
            dentry: self.dentry.clone(),
            path_len: self.path_len,
            path: self.path,
        };
        cloned.retain_ramfs_inode();
        cloned
    }
}

impl Drop for OpenFile {
    fn drop(&mut self) {
        self.release_ramfs_inode();
    }
}

impl fmt::Debug for OpenFile {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("OpenFile")
            .field("inode", &self.inode)
            .field("file_type", &self.file_type)
            .field("offset", &self.offset)
            .field("access", &self.access)
            .field("ops", &self.file_ops().name())
            .field("path", &self.path())
            .finish()
    }
}

impl PartialEq for OpenFile {
    fn eq(&self, other: &Self) -> bool {
        self.inode == other.inode
            && self.file_type == other.file_type
            && self.offset == other.offset
            && self.access == other.access
            && self.path() == other.path()
            && self.file_ops().name() == other.file_ops().name()
    }
}

impl Eq for OpenFile {}

