const STATUS_ACKNOWLEDGE: u32 = 1;
const STATUS_DRIVER: u32 = 2;
const STATUS_DRIVER_OK: u32 = 4;
const STATUS_FEATURES_OK: u32 = 8;
const STATUS_FAILED: u32 = 128;

const VIRTIO_F_VERSION_1_PAGE1: u32 = 1;
const VIRTIO_MMIO_VERSION_LEGACY: u32 = 1;
const VIRTIO_MMIO_VERSION_MODERN: u32 = 2;

const DMA_PHYS_MASK: usize = (1usize << 48) - 1;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum TransportKind {
    Mmio,
    PciModern,
}

struct VirtioBlk {
    base: usize,
    version: u32,
    transport: TransportKind,
    notify_base: usize,
    notify_multiplier: u32,
    notify_offset: u16,
    ready: bool,
    last_used_idx: u16,
}

impl VirtioBlk {
    const fn empty() -> Self {
        Self {
            base: 0,
            version: 0,
            transport: TransportKind::Mmio,
            notify_base: 0,
            notify_multiplier: 0,
            notify_offset: 0,
            ready: false,
            last_used_idx: 0,
        }
    }

    fn init_mmio(
        &mut self,
        base: usize,
        version: u32,
        queue: &mut QueueMemory,
    ) -> Result<(), BlockError> {
        self.base = base;
        self.version = version;
        self.transport = TransportKind::Mmio;
        self.notify_base = 0;
        self.notify_multiplier = 0;
        self.notify_offset = 0;
        self.ready = false;
        queue.avail = AvailRing::new();
        queue.used = UsedRing::new();
        write32(base, 0x070, 0);
        write32(base, 0x070, STATUS_ACKNOWLEDGE);
        write32(base, 0x070, STATUS_ACKNOWLEDGE | STATUS_DRIVER);

        match version {
            VIRTIO_MMIO_VERSION_LEGACY => self.init_legacy_queue(queue)?,
            VIRTIO_MMIO_VERSION_MODERN => self.init_modern_queue(queue)?,
            _ => {
                write32(base, 0x070, STATUS_FAILED);
                return Err(BlockError::Io);
            }
        }

        self.last_used_idx = queue::read_used_idx(queue);
        let status = if version == VIRTIO_MMIO_VERSION_MODERN {
            STATUS_ACKNOWLEDGE | STATUS_DRIVER | STATUS_FEATURES_OK | STATUS_DRIVER_OK
        } else {
            STATUS_ACKNOWLEDGE | STATUS_DRIVER | STATUS_DRIVER_OK
        };
        write32(base, 0x070, status);
        self.ready = true;
        Ok(())
    }

    fn init_pci_modern(
        &mut self,
        device: pci::VirtioPciDevice,
        queue: &mut QueueMemory,
    ) -> Result<(), BlockError> {
        self.base = device.common_cfg;
        self.version = VIRTIO_MMIO_VERSION_MODERN;
        self.transport = TransportKind::PciModern;
        self.notify_base = device.notify_base;
        self.notify_multiplier = device.notify_multiplier;
        self.notify_offset = 0;
        self.ready = false;
        queue.avail = AvailRing::new();
        queue.used = UsedRing::new();

        pci_write_status(self.base, 0);
        pci_write_status(self.base, STATUS_ACKNOWLEDGE as u8);
        pci_write_status(self.base, (STATUS_ACKNOWLEDGE | STATUS_DRIVER) as u8);

        pci_write32(self.base, 0x08, 0);
        pci_write32(self.base, 0x0c, 0);
        pci_write32(self.base, 0x08, 1);
        pci_write32(self.base, 0x0c, VIRTIO_F_VERSION_1_PAGE1);
        pci_write_status(
            self.base,
            (STATUS_ACKNOWLEDGE | STATUS_DRIVER | STATUS_FEATURES_OK) as u8,
        );
        if pci_read_status(self.base) as u32 & STATUS_FEATURES_OK == 0 {
            pci_write_status(self.base, STATUS_FAILED as u8);
            return Err(BlockError::Io);
        }

        pci_write16(self.base, 0x16, 0);
        let max = pci_read16(self.base, 0x18);
        if max < VIRTQ_LEN as u16 {
            pci_write_status(self.base, STATUS_FAILED as u8);
            return Err(BlockError::Io);
        }
        pci_write16(self.base, 0x18, VIRTQ_LEN as u16);
        self.notify_offset = pci_read16(self.base, 0x1e);

        let desc = self.dma_addr(queue.desc.as_ptr() as usize);
        let avail = self.dma_addr(core::ptr::addr_of!(queue.avail) as usize);
        let used = self.dma_addr(core::ptr::addr_of!(queue.used) as usize);
        pci_write64(self.base, 0x20, desc);
        pci_write64(self.base, 0x28, avail);
        pci_write64(self.base, 0x30, used);
        pci_write16(self.base, 0x1c, 1);

        self.last_used_idx = queue::read_used_idx(queue);
        pci_write_status(
            self.base,
            (STATUS_ACKNOWLEDGE | STATUS_DRIVER | STATUS_FEATURES_OK | STATUS_DRIVER_OK) as u8,
        );
        self.ready = true;
        Ok(())
    }

    fn init_legacy_queue(&mut self, queue: &mut QueueMemory) -> Result<(), BlockError> {
        let base = self.base;
        write32(base, 0x020, 0);
        write32(base, 0x028, PAGE_SIZE as u32);
        write32(base, 0x030, 0);
        let max = read32(base, 0x034);
        if max < VIRTQ_LEN as u32 {
            write32(base, 0x070, STATUS_FAILED);
            return Err(BlockError::Io);
        }
        write32(base, 0x038, VIRTQ_LEN as u32);
        write32(base, 0x03c, PAGE_SIZE as u32);
        let queue_addr = queue.desc.as_ptr() as usize;
        if queue_addr & (PAGE_SIZE - 1) != 0 {
            write32(base, 0x070, STATUS_FAILED);
            return Err(BlockError::Io);
