        .ok_or(Ext4Error::Unsupported)?;
    if block_size == 0 || block_size > 4096 {
        return Err(Ext4Error::Unsupported);
    }
    let inode_size = le16(&sb, 88);
    if inode_size < 128 {
        return Err(Ext4Error::Unsupported);
    }
    let desc_size = {
        let raw = le16(&sb, 254);
        if raw < 32 {
            32
        } else {
            raw
        }
    };
    if desc_size > 64 {
        return Err(Ext4Error::Unsupported);
    }
    let first_data_block = le32(&sb, 20);
    let group_desc_table_block = if block_size == 1024 { 2 } else { 1 };
    *STATE.lock() = Ext4State {
        mounted: true,
        block_size,
        inodes_per_group: le32(&sb, 40),
        blocks_per_group: le32(&sb, 32),
        inode_size,
        desc_size,
        first_data_block,
        group_desc_table_block,
        blocks_count: le32(&sb, 4) as u64,
        free_blocks_count: le32(&sb, 12) as u64,
        inodes_count: le32(&sb, 0) as u64,
        free_inodes_count: le32(&sb, 16) as u64,
    };
    Ok(())
}

pub fn is_mounted() -> bool {
    STATE.lock().mounted
}

pub fn stat(inode_no: u32) -> Result<Metadata, Ext4Error> {
    let inode = read_inode(inode_no)?;
    Ok(Metadata {
        inode: NodeId::ext4(inode_no),
        mode: inode.mode,
        file_type: file_type_from_mode(inode.mode),
        rdev: DeviceId::ZERO,
        nlink: inode.links_count as u32,
        uid: 0,
        gid: 0,
        size: inode.size,
        times: FileTimes::ZERO,
        flags: 0,
    })
}

pub fn statfs() -> Result<FsStat, Ext4Error> {
    let state = *STATE.lock();
    if !state.mounted {
        return Err(Ext4Error::Invalid);
    }
    Ok(FsStat {
        fs_type: 0xef53,
        block_size: state.block_size as u64,
        blocks: state.blocks_count,
        blocks_free: state.free_blocks_count,
        blocks_available: state.free_blocks_count,
        files: state.inodes_count,
        files_free: state.free_inodes_count,
        name_len: 255,
        fragment_size: state.block_size as u64,
        flags: 0,
    })
}

pub fn lookup(parent_inode: u32, name: &[u8]) -> Result<u32, Ext4Error> {
    let parent = read_inode(parent_inode)?;
    if file_type_from_mode(parent.mode) != FileType::Directory {
        return Err(Ext4Error::NotDirectory);
    }
    let mut pos = 0u64;
    while pos < parent.size {
        let Some(entry) = read_dir_entry(&parent, pos)? else {
            break;
        };
        if entry.name() == name {
            return Ok(entry.inode as u32);
        }
        pos = entry.offset;
    }
    Err(Ext4Error::NotFound)
}

pub fn read_at(inode_no: u32, offset: u64, out: &mut [u8]) -> Result<usize, Ext4Error> {
    let inode = read_inode(inode_no)?;
    if file_type_from_mode(inode.mode) != FileType::Regular {
        return Err(Ext4Error::Invalid);
    }
    read_inode_bytes(&inode, offset, out)
}

