const LOOPBACK_PREFIX_LEN: u8 = 8;
const TCP_BUFFER_BYTES: usize = 64 * 1024;
const UDP_BUFFER_BYTES: usize = 64 * 1024;
const UDP_PACKET_SLOTS: usize = 64;

pub struct LoopbackStack {
    iface: Interface,
    device: LoopbackDevice,
    sockets: SocketSet<'static>,
}

impl LoopbackStack {
    pub fn new() -> Self {
        let mut device = LoopbackDevice::new();
        let config = Config::new(HardwareAddress::Ip);
        let mut iface = Interface::new(config, &mut device, current_instant());
        iface.update_ip_addrs(|addrs| {
            addrs
                .push(IpCidr::new(LOOPBACK_ADDR, LOOPBACK_PREFIX_LEN))
                .expect("loopback interface address storage");
        });

        Self {
            iface,
            device,
            sockets: SocketSet::new(Vec::new()),
        }
    }

    pub fn poll(&mut self) {
        let now = current_instant();
        let _ = self.iface.poll(now, &mut self.device, &mut self.sockets);
    }

    pub fn add_tcp_socket(&mut self) -> SocketHandle {
        let rx = tcp::SocketBuffer::new(vec![0; TCP_BUFFER_BYTES]);
        let tx = tcp::SocketBuffer::new(vec![0; TCP_BUFFER_BYTES]);
        self.sockets.add(tcp::Socket::new(rx, tx))
    }

    pub fn add_udp_socket(&mut self) -> SocketHandle {
        let rx_meta = vec![udp::PacketMetadata::EMPTY; UDP_PACKET_SLOTS];
        let rx_data = vec![0; UDP_BUFFER_BYTES];
        let tx_meta = vec![udp::PacketMetadata::EMPTY; UDP_PACKET_SLOTS];
        let tx_data = vec![0; UDP_BUFFER_BYTES];
        let rx = udp::PacketBuffer::new(rx_meta, rx_data);
        let tx = udp::PacketBuffer::new(tx_meta, tx_data);
        self.sockets.add(udp::Socket::new(rx, tx))
    }

    pub fn tcp_listen(&mut self, handle: SocketHandle, port: u16) {
        let endpoint = IpListenEndpoint {
            addr: Some(LOOPBACK_ADDR),
            port,
        };
        self.sockets
            .get_mut::<tcp::Socket>(handle)
            .listen(endpoint)
            .expect("listen on loopback tcp socket");
    }

    pub fn tcp_connect(&mut self, handle: SocketHandle, remote_port: u16, local_port: u16) {
        let remote = IpEndpoint::from((LOOPBACK_ADDR, remote_port));
        let local = IpListenEndpoint {
            addr: Some(LOOPBACK_ADDR),
            port: local_port,
        };
        self.sockets
            .get_mut::<tcp::Socket>(handle)
            .connect(self.iface.context(), remote, local)
            .expect("connect loopback tcp socket");
    }

    pub fn tcp_can_send(&self, handle: SocketHandle) -> bool {
        self.sockets.get::<tcp::Socket>(handle).can_send()
    }

    pub fn tcp_can_recv(&self, handle: SocketHandle) -> bool {
        self.sockets.get::<tcp::Socket>(handle).can_recv()
    }

    pub fn tcp_send(&mut self, handle: SocketHandle, bytes: &[u8]) -> usize {
        self.sockets
            .get_mut::<tcp::Socket>(handle)
            .send_slice(bytes)
            .expect("send on loopback tcp socket")
    }

    pub fn tcp_recv(&mut self, handle: SocketHandle, out: &mut [u8]) -> usize {
        self.sockets
            .get_mut::<tcp::Socket>(handle)
            .recv_slice(out)
            .expect("recv on loopback tcp socket")
    }

    pub fn udp_bind(&mut self, handle: SocketHandle, port: u16) {
        let endpoint = IpListenEndpoint {
            addr: Some(LOOPBACK_ADDR),
            port,
        };
        self.sockets
            .get_mut::<udp::Socket>(handle)
            .bind(endpoint)
            .expect("bind loopback udp socket");
    }

    pub fn udp_can_recv(&self, handle: SocketHandle) -> bool {
        self.sockets.get::<udp::Socket>(handle).can_recv()
    }

    pub fn udp_send(&mut self, handle: SocketHandle, remote_port: u16, bytes: &[u8]) -> usize {
        let endpoint = IpEndpoint::from((LOOPBACK_ADDR, remote_port));
        self.sockets
            .get_mut::<udp::Socket>(handle)
            .send_slice(bytes, endpoint)
            .expect("send on loopback udp socket");
        bytes.len()
    }

    pub fn udp_recv(&mut self, handle: SocketHandle, out: &mut [u8]) -> (usize, IpEndpoint) {
        let (read, meta) = self
            .sockets
            .get_mut::<udp::Socket>(handle)
            .recv_slice(out)
            .expect("recv on loopback udp socket");
        (read, meta.endpoint)
    }
}

