        }
    }
}

impl Device for LoopbackDevice {
    type RxToken<'a> = LoopbackRxToken;
    type TxToken<'a> = LoopbackTxToken<'a>;

    fn receive(&mut self, _timestamp: Instant) -> Option<(Self::RxToken<'_>, Self::TxToken<'_>)> {
        self.queue.pop_front().map(|packet| {
            (
                LoopbackRxToken { packet },
                LoopbackTxToken {
                    queue: &mut self.queue,
                },
            )
        })
    }

    fn transmit(&mut self, _timestamp: Instant) -> Option<Self::TxToken<'_>> {
        Some(LoopbackTxToken {
            queue: &mut self.queue,
        })
    }

    fn capabilities(&self) -> DeviceCapabilities {
        let mut caps = DeviceCapabilities::default();
        caps.medium = Medium::Ip;
        caps.max_transmission_unit = 65_535;
        caps.checksum = ChecksumCapabilities::ignored();
        caps
    }
}

pub struct LoopbackRxToken {
    packet: Vec<u8>,
}

impl phy::RxToken for LoopbackRxToken {
    fn consume<R, F>(self, f: F) -> R
    where
        F: FnOnce(&[u8]) -> R,
    {
        f(&self.packet)
    }
}

pub struct LoopbackTxToken<'a> {
    queue: &'a mut VecDeque<Vec<u8>>,
}

impl phy::TxToken for LoopbackTxToken<'_> {
    fn consume<R, F>(self, len: usize, f: F) -> R
    where
        F: FnOnce(&mut [u8]) -> R,
    {
        let mut packet = vec![0; len];
        let result = f(&mut packet);
        self.queue.push_back(packet);
        result
    }
}

use super::pid::TaskLookup;

pub(super) trait SchedulableTask: TaskLookup {
    fn is_ready(&self) -> bool;
}

pub(super) struct UserScheduler {
    cursor: usize,
}

impl UserScheduler {
    pub(super) const fn new() -> Self {
        Self { cursor: 0 }
    }

    pub(super) fn reset(&mut self) {
        self.cursor = 0;
    }

    pub(super) fn start_after(&mut self, index: usize, len: usize) {
        if len == 0 {
            self.cursor = 0;
        } else {
            self.cursor = (index + 1) % len;
        }
    }

    pub(super) fn take_next_ready_pid<T: SchedulableTask>(
        &mut self,
        ready_indices: &[usize],
        tasks: &[T],
    ) -> Option<usize> {
        if ready_indices.is_empty() || tasks.is_empty() {
            return None;
        }
        self.take_ready_pid_from(ready_indices, tasks, self.cursor)
            .or_else(|| self.take_ready_pid_from(ready_indices, tasks, 0))
    }

    fn take_ready_pid_from<T: SchedulableTask>(
        &mut self,
        ready_indices: &[usize],
        tasks: &[T],
        start_index: usize,
    ) -> Option<usize> {
        for &index in ready_indices {
            if index < start_index {
                continue;
            }
            let Some(task) = tasks.get(index) else {
                continue;
            };
            if task.is_ready() {
                self.cursor = (index + 1) % tasks.len();
                return Some(task.pid());
            }
        }
        None
    }
}

