struct SocketTable {
    pub(super) entries: [Option<SocketState>; MAX_SOCKETS],
    pub(super) next_id: usize,
    pub(super) next_port: u16,
}

impl SocketTable {
    const fn new() -> Self {
        Self {
            entries: [const { None }; MAX_SOCKETS],
            next_id: 1,
            next_port: EPHEMERAL_FIRST,
        }
    }

    fn create(&mut self, domain: SocketDomain, kind: SocketKind) -> Result<SocketEndpoint, isize> {
        Ok(SocketEndpoint {
            id: self.insert_socket(domain, kind)?,
        })
    }

    fn insert_socket(&mut self, domain: SocketDomain, kind: SocketKind) -> Result<usize, isize> {
        let index = self
            .entries
            .iter()
            .position(Option::is_none)
            .ok_or(EMFILE)?;
        let id = self.next_id;
        self.next_id = self.next_id.wrapping_add(1).max(1);
        self.entries[index] = Some(SocketState::new(id, domain, kind));
        Ok(id)
    }

    fn remove(&mut self, id: usize) {
        if let Some(index) = self
            .entries
            .iter()
            .position(|entry| entry.as_ref().is_some_and(|socket| socket.id == id))
        {
            let mut pending_ids = [0usize; MAX_TCP_PENDING];
            let mut pending_count = 0usize;
            if let Some(socket) = self.entries[index].as_ref() {
                for pending in socket.pending.iter().flatten() {
                    pending_ids[pending_count] = pending.endpoint_id;
                    pending_count += 1;
                }
            }
            self.entries[index] = None;
            for pending_id in pending_ids[..pending_count].iter().copied() {
                self.remove(pending_id);
            }
        }
    }

    fn close(&mut self, id: usize) -> SocketCloseEvent {
        let event = self.close_event(id);
        self.remove(id);
        event
    }

    fn close_event(&mut self, id: usize) -> SocketCloseEvent {
        let Ok(source_index) = self.index_of(id) else {
            return SocketCloseEvent::default();
        };
        let (kind, source_port, peer) = {
            let Some(source) = self.entries[source_index].as_ref() else {
                return SocketCloseEvent::default();
            };
            (source.kind, source.local_port, source.peer)
        };
        if kind != SocketKind::Stream {
            return SocketCloseEvent::default();
        }
        let Some(peer) = peer else {
            return SocketCloseEvent::default();
        };
        let Some(target_index) = self.stream_peer_index(source_port, peer.port) else {
            return SocketCloseEvent::default();
        };
        let Some(target) = self.entries[target_index].as_mut() else {
            return SocketCloseEvent::default();
        };
        target.recv_shutdown = true;
        SocketCloseEvent {
            wake_reader: Some(target.id),
            wake_writer: Some(target.id),
        }
    }

    fn bind(&mut self, id: usize, addr: InetSocketAddr) -> Result<(), isize> {
        if addr.addr != 0 && addr.addr != LOOPBACK_ADDR {
            return Err(EADDRNOTAVAIL);
        }
        let index = self.index_of(id)?;
        let state = self.entries[index].as_ref().ok_or(ENOTSOCK)?;
        state.ensure_inet()?;
        if state.bound {
            return Err(EINVAL);
        }
        let (kind, reuse_addr) = (state.kind, state.reuse_addr);
        let port = if addr.port == 0 {
            self.allocate_ephemeral_port(kind)?
        } else {
            addr.port
        };
        if self.bound_port_conflicts(kind, port, id, reuse_addr) {
            return Err(EADDRINUSE);
        }
        let state = self.entries[index].as_mut().ok_or(ENOTSOCK)?;
        state.bound = true;
        state.local_addr = addr.addr;
        state.local_port = port;
        if kind == SocketKind::Datagram && reuse_addr {
            self.redistribute_queued_datagrams_to_listener(index);
        }
        Ok(())

