pub fn load_static_elf(
    bytes: &[u8],
    argv: &[&str],
    envp: &[&str],
) -> Result<LoadedElf, ElfLoadError> {
    load_elf_with_resolver(bytes, argv, envp, "/", &mut NoInterpreterResolver)
}

pub trait InterpreterResolver {
    fn ensure(&mut self, path: &str) -> bool;
    fn bytes(&self) -> Option<&[u8]>;
}

pub fn load_elf_with_resolver(
    bytes: &[u8],
    argv: &[&str],
    envp: &[&str],
    variant_root: &str,
    resolver: &mut impl InterpreterResolver,
) -> Result<LoadedElf, ElfLoadError> {
    let header = ElfHeader::parse(bytes)?;
    header.validate_program_header_table(bytes)?;
    let mut memory = MemorySet::empty_user()?;
    let main_base = if header.elf_type == ET_DYN {
        USER_DYN_LOAD_BASE
    } else {
        0
    };
    let main = load_image(&mut memory, bytes, &header, main_base)?;
    let mut user_entry = main.entry;
    let mut aux_base = 0usize;

    if let Some(interp_path) = main.interp_path.as_deref() {
        let interp_bytes = resolve_interpreter(interp_path, variant_root, resolver)
            .ok_or(ElfLoadError::Unsupported)?;
        let patched_interp =
            maybe_patch_loongarch_musl_interpreter(interp_path, variant_root, interp_bytes);
        let interp_bytes = patched_interp.as_deref().unwrap_or(interp_bytes);
        let interp_header = ElfHeader::parse(interp_bytes)?;
        interp_header.validate_program_header_table(interp_bytes)?;
        if interp_header.elf_type != ET_DYN {
            return Err(ElfLoadError::Unsupported);
        }
        let interp = load_image(&mut memory, interp_bytes, &interp_header, INTERP_LOAD_BASE)?;
        user_entry = interp.entry;
        aux_base = interp.base;
    }

    let stack_bottom = USER_STACK_TOP - USER_STACK_SIZE;
    memory.map_user_stack(VirtAddr(stack_bottom), VirtAddr(USER_STACK_TOP))?;
    let stack_top = super::stack::build_initial_stack(
        &memory,
        USER_STACK_TOP,
        argv,
        envp,
        super::stack::AuxValues {
            entry: main.entry,
            phdr: main.phdr,
            phent: header.phentsize as usize,
            phnum: header.phnum as usize,
            page_size: PAGE_SIZE,
            base: aux_base,
            uid: 0,
            euid: 0,
            gid: 0,
            egid: 0,
            secure: 0,
        },
    )
    .map_err(|_| ElfLoadError::SegmentOutOfRange)?;

    let heap_base =
        checked_align_up(main.highest_loaded, PAGE_SIZE).ok_or(ElfLoadError::SegmentOutOfRange)?;
    memory.init_brk(VirtAddr(heap_base))?;

    Ok(LoadedElf {
        memory,
        entry: user_entry,
        stack_top,
        heap_base,
    })
}

