pub fn sys_times(addr: usize) -> SyscallRet {
    let ticks = process_cpu_ticks_now();
    if addr != 0 {
        let Some(result) = with_current_user_mut(|task| {
            let cpu = task.cpu_times(ticks);
            let values = [
                cpu.user_ticks as isize,
                cpu.system_ticks as isize,
                cpu.children_user_ticks as isize,
                cpu.children_system_ticks as isize,
            ];
            let bytes = unsafe {
                // SAFETY: from_raw_parts creates a byte slice view of the
                // stack-allocated `values` array. The array's memory layout
                // is contiguous and the slice length (values.len() * size_of::<isize>())
                // exactly covers all bytes of the array. The resulting slice
                // is used immediately and does not outlive the array.
                core::slice::from_raw_parts(
                    values.as_ptr() as *const u8,
                    values.len() * core::mem::size_of::<isize>(),
                )
            };
            task.memory.write_user_bytes(addr, bytes)
        }) else {
            return err(EPERM);
        };
        if result.is_err() {
            return err(EFAULT);
        }
    }
    ticks as isize
}

pub fn sys_nanosleep(req_addr: usize, rem_addr: usize) -> SyscallRet {
    if req_addr == 0 {
        return err(EFAULT);
    }
    let mut table = USER_PROCESSES.lock();
    let Some(index) = table.current_index() else {
        return err(EPERM);
    };
    if table.tasks[index].state != UserTaskState::Running {
        return err(EPERM);
    }
    if table.tasks[index].pending_sync_signal == Some(super::super::signal::SIGCANCEL) {
        return finish_interrupted_nanosleep(&mut table.tasks[index], rem_addr);
    }
    let current_pid = table.tasks[index].pid;
    if table.take_signal_wake(current_pid).is_some()
        || table.take_wake_reason(current_pid, WakeReason::SignalPending)
    {
        return finish_interrupted_nanosleep(&mut table.tasks[index], rem_addr);
    }
    if table.take_wake_reason(current_pid, WakeReason::Timeout) {
        return finish_nanosleep(&mut table.tasks[index], rem_addr);
    }
    let now = crate::arch::uptime_micros();
    if let Some(deadline) = table.tasks[index].sleep_deadline_micros {
        if now < deadline {
            table.tasks[index].state = UserTaskState::Sleeping;
            table.rebuild_indexes();
            return SYSCALL_BLOCKED;
        }
        clear_sleep_state(&mut table.tasks[index]);
    } else {
        let sleep_micros = match read_timespec_micros(&table.tasks[index], req_addr) {
            Ok(micros) => micros,
            Err(errno) => return err(errno),
        };
        let deadline = now.saturating_add(sleep_micros);
        if deadline > now {
            if !table.sleep_current_until_reporting_remaining(deadline) {
                return err(EPERM);
            }
            return SYSCALL_BLOCKED;
        }
    }

    finish_nanosleep(&mut table.tasks[index], rem_addr)
}

fn finish_nanosleep(task: &mut UserTask, rem_addr: usize) -> SyscallRet {
    clear_sleep_state(task);
    if rem_addr != 0 {
        if write_timespec_micros(task, rem_addr, 0).is_err() {
            return err(EFAULT);
        }
    }
    0
}

fn finish_interrupted_nanosleep(task: &mut UserTask, rem_addr: usize) -> SyscallRet {
    let remaining = task.interrupted_sleep_remaining_micros.take().unwrap_or(0);
    clear_sleep_state(task);
    if rem_addr != 0 && write_timespec_micros(task, rem_addr, remaining).is_err() {
        return err(EFAULT);
    }
    err(EINTR)

