/*
 * RISC-V64 QEMU linker script.
 *
 * Memory layout:
 *   BASE_ADDRESS (0x80200000) — QEMU virt machine default load address
 *   .text — kernel code (read-only, executable)
 *   .rodata — read-only data
 *   .data — initialized data
 *   .bss — zero-initialized data (sbss to ebss cleared by rust_entry)
 *
 * Debug sections (.eh_frame, .debug_*) are discarded (/DISCARD/) to
 * reduce binary size.  The kernel is a static binary with no unwinding.
 */
OUTPUT_ARCH(riscv)
ENTRY(_start)

BASE_ADDRESS = 0x80200000;

SECTIONS
{
    . = BASE_ADDRESS;
    skernel = .;

    .text : {
        stext = .;
        *(.text.entry)
        *(.text .text.*)
        etext = .;
    }

    .rodata : ALIGN(4K) {
        srodata = .;
        *(.rodata .rodata.*)
    }

    .srodata : ALIGN(8) {
        *(.srodata .srodata.*)
        erodata = .;
    }

    .data : ALIGN(4K) {
        sdata = .;
        *(.sdata .sdata.*)
        *(.data .data.*)
        edata = .;
    }

    .bss : ALIGN(4K) {
        sbss = .;
        *(.sbss .sbss.*)
        *(.bss .bss.*)
        *(COMMON)
        ebss = .;
    }

    .boot_stack (NOLOAD) : ALIGN(4K) {
        *(.boot_stack)
    }

    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame)
        *(.debug_*)
        *(.comment)
    }
}

