pub fn sys_brk(addr: usize) -> SyscallRet {
    let Some(result) = process::with_current_user_mut(|task| {
        let old = task.memory.brk().as_usize();
        if addr == 0 {
            return old;
        }
        let Some(max_brk) = task
            .memory
            .brk_start()
            .as_usize()
            .checked_add(MAX_USER_BRK_SIZE)
        else {
            return old;
        };
        if addr > max_brk {
            return old;
        }
        match task.memory.set_brk(VirtAddr(addr)) {
            Ok(()) => task.memory.brk().as_usize(),
            Err(_) => old,
        }
    }) else {
        return err(EPERM);
    };
    result as isize
}

pub fn sys_get_mempolicy(
    mode_addr: usize,
    nodemask_addr: usize,
    maxnode: usize,
    _addr: usize,
    flags: usize,
) -> SyscallRet {
    if flags != 0 || maxnode > MAX_MEMPOLICY_NODES {
        return err(EINVAL);
    }
    let Some(result) = process::with_current_user(|task| {
        if mode_addr != 0 {
            UserBuffer::new(mode_addr, core::mem::size_of::<i32>())
                .write(task.memory.page_table(), &0i32.to_ne_bytes())
                .map_err(|_| EFAULT)?;
        }
        if nodemask_addr != 0 {
            if maxnode == 0 {
                return Err(EINVAL);
            }
            let words = maxnode.saturating_add(usize::BITS as usize - 1) / usize::BITS as usize;
            for index in 0..words {
                let addr = nodemask_addr
                    .checked_add(index * core::mem::size_of::<usize>())
                    .ok_or(EFAULT)?;
                UserBuffer::new(addr, core::mem::size_of::<usize>())
                    .write(task.memory.page_table(), &0usize.to_ne_bytes())
                    .map_err(|_| EFAULT)?;
            }
        }
        Ok(0)
    }) else {
        return err(EPERM);
    };
    result.unwrap_or_else(err)
}

