use core::sync::atomic::{AtomicU64, Ordering};

pub const TICKS_PER_SECOND: u64 = 100;

static TICKS: AtomicU64 = AtomicU64::new(0);

#[derive(Clone, Copy, Debug, Eq, PartialEq, Ord, PartialOrd)]
pub struct MonotonicTicks(pub u64);

pub fn init() {
    TICKS.store(0, Ordering::SeqCst);
}

pub fn on_timer_tick() -> MonotonicTicks {
    MonotonicTicks(TICKS.fetch_add(1, Ordering::SeqCst) + 1)
}

pub fn monotonic_ticks() -> MonotonicTicks {
    MonotonicTicks(TICKS.load(Ordering::SeqCst))
}

pub fn uptime_micros() -> u64 {
    monotonic_ticks().0.saturating_mul(1_000_000) / TICKS_PER_SECOND
}

use alloc::vec::Vec;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct TimerWake {
    pub(crate) task_id: usize,
    pub(crate) deadline_micros: u64,
}

pub struct TimerQueue {
    timers: Vec<TimerWake>,
}

impl TimerQueue {
    pub const fn new() -> Self {
        Self { timers: Vec::new() }
    }

    pub fn sleep_until(&mut self, task_id: usize, deadline_micros: u64) {
        self.cancel(task_id);
        self.timers.push(TimerWake {
            task_id,
            deadline_micros,
        });
    }

    pub fn cancel(&mut self, task_id: usize) -> bool {
        let Some(index) = self
            .timers
            .iter()
            .position(|timer| timer.task_id == task_id)
        else {
            return false;
        };
        self.timers.remove(index);
        true
    }

    pub fn next_deadline(&self) -> Option<u64> {
        self.timers.iter().map(|timer| timer.deadline_micros).min()
    }

    pub fn pop_expired(&mut self, now_micros: u64) -> Option<TimerWake> {
        let index = self.earliest_expired_index(now_micros)?;
        Some(self.timers.remove(index))
    }

    pub fn expire_ready(&mut self, now_micros: u64) -> Vec<TimerWake> {
        let mut out = Vec::new();
        while let Some(wake) = self.pop_expired(now_micros) {
            out.push(wake);
        }
        out
    }

    fn earliest_expired_index(&self, now_micros: u64) -> Option<usize> {
        self.timers
            .iter()
            .enumerate()
            .filter(|(_, timer)| timer.deadline_micros <= now_micros)
            .min_by_key(|(index, timer)| (timer.deadline_micros, *index))
            .map(|(index, _)| index)
    }
}

