    const ROOT_CAPS: u64 = (1u64 << 13) // CAP_NET_RAW
        | (1u64 << 14) // CAP_IPC_LOCK
        | (1u64 << 18) // CAP_SYS_CHROOT
        | (1u64 << 21) // CAP_SYS_ADMIN
        | (1u64 << 23) // CAP_SYS_NICE
        | (1u64 << 24) // CAP_SYS_RESOURCE
        | (1u64 << Self::CAP_SYS_TIME);

    pub const fn root() -> Self {
        Self {
