            fsgid: 0,
            supplementary_groups: [0; SUPPLEMENTARY_GROUPS_MAX],
            supplementary_group_count: 0,
            cap_effective: Self::ROOT_CAPS,
            cap_permitted: Self::ROOT_CAPS,
            cap_inheritable: 0,
        }
    }

    pub const fn has_root_uid(self) -> bool {
        self.uid == 0 || self.euid == 0 || self.suid == 0
    }

    pub(crate) fn supplementary_groups(&self) -> &[u32] {
        &self.supplementary_groups[..self.supplementary_group_count]
    }

    pub(crate) fn set_supplementary_groups(&mut self, groups: &[u32]) {
        self.supplementary_group_count = groups.len();
        self.supplementary_groups[..groups.len()].copy_from_slice(groups);
        self.supplementary_groups[groups.len()..].fill(0);
    }

    pub(crate) fn is_in_group(&self, gid: u32) -> bool {
        self.fsgid as u32 == gid || self.supplementary_groups().contains(&gid)
    }

    pub(crate) fn has_effective_capability(&self, cap: usize) -> bool {
        cap < u64::BITS as usize && (self.cap_effective & (1u64 << cap)) != 0
    }

    pub(crate) fn may_chmod_inode(&self, owner_uid: u32) -> bool {
        self.euid == 0 || self.euid as u32 == owner_uid
    }

    pub(crate) fn chmod_mode_for_inode(&self, owner_gid: u32, mode: u32) -> u32 {
        if mode & S_ISGID != 0 && self.euid != 0 && !self.is_in_group(owner_gid) {
            mode & !S_ISGID
        } else {
            mode
        }
    }
}

