pub(in crate::syscall::process) fn send_signal_to_task_index(
    table: &mut UserProcessTable,
    index: usize,
    signum: usize,
) -> SyscallRet {
    if table.tasks[index].state == UserTaskState::Zombie {
        return err(ESRCH);
    }
    if signum == 0 {
        return 0;
    }
    let default_action = table.tasks[index].signal_actions.get(signum).handler == 0;
    let masked = table.tasks[index].signal_mask & signal_bit(signum) != 0;
    trace_signal_delivery(&table.tasks[index], signum, masked);
    if table.tasks[index].signal_actions.get(signum).handler == super::SIG_IGN {
        return 0;
    }
    if signum == SIGKILL || (is_default_terminate_signal(signum) && default_action && !masked) {
        terminate_task_by_signal(table, index, signum);
    } else if is_default_terminate_signal(signum) && default_action && masked {
        table.tasks[index].pending_sync_signal = Some(signum);
    } else if !default_action {
        if masked {
            table.tasks[index].pending_sync_signal = Some(signum);
        } else {
            queue_or_deliver_signal_handler_to_task(table, index, signum);
        }
    }
    0
}

pub(in crate::syscall::process) fn queue_or_deliver_signal_handler_to_task(
    table: &mut UserProcessTable,
    index: usize,
    signum: usize,
) -> bool {
    if mark_current_sync_signal(table, index, signum) {
        return true;
    }
    deliver_signal_handler_to_task(table, index, signum)
}

fn mark_current_sync_signal(table: &mut UserProcessTable, index: usize, signum: usize) -> bool {
    let current = table.pids.current();
    if current != Some(table.tasks[index].pid) || table.tasks[index].state != UserTaskState::Running
    {
        return false;
    }
    table.tasks[index].pending_sync_signal = Some(signum);
    true
}

fn deliver_signal_handler_to_task(
    table: &mut UserProcessTable,
    index: usize,
    signum: usize,
) -> bool {
    let action = table.tasks[index].signal_actions.get(signum);
    if action.handler == 0 || action.handler == super::SIG_IGN {
        trace_signal_delivery_result(&table.tasks[index], signum, "no-handler", 0, 0, 0, 0);
        return false;
    }
    if signum == SIGCANCEL && sigcancel_deferred_by_musl_cancel_disable(&table.tasks[index]) {
        table.tasks[index].pending_sync_signal = Some(signum);
        trace_signal_delivery_result(&table.tasks[index], signum, "cancel-disabled", 0, 0, 0, 0);
        return false;
    }
    let pid = table.tasks[index].pid;
    let restore_frame = match table.tasks[index].trap_frame.as_ref() {
        Some(frame) => *frame,
        None => {
            trace_signal_delivery_result(&table.tasks[index], signum, "no-frame", 0, 0, 0, 0);
            return false;
        }
    };
    let interrupted_pc = restore_frame.user_pc();
    let interrupted_sp = restore_frame.user_sp();
    let Some(frame_addrs) = build_sigcancel_frame(
        &mut table.tasks[index],
        signum,
        interrupted_pc,
        interrupted_sp,
    ) else {
        trace_signal_delivery_result(
            &table.tasks[index],
            signum,
            "frame-build-failed",
            interrupted_pc,
            interrupted_sp,
            0,
            0,
        );
        return false;
    };
    let interrupt_wait = should_interrupt_wait_for_signal(&table.tasks[index], signum);
    let restorer = match resolve_signal_restorer(&mut table.tasks[index], action.restorer) {
        Ok(restorer) => restorer,
        Err(()) => {
            trace_signal_delivery_result(
                &table.tasks[index],
                signum,
                "restorer-failed",
                interrupted_pc,
                interrupted_sp,
                frame_addrs.frame_base,
                0,
            );
            return false;
        }
    };
    table.tasks[index].signal_restore_frame = Some(restore_frame);
    table.tasks[index].signal_mask =
        signal_handler_mask(table.tasks[index].signal_mask, signum, action.mask);
    let Some(frame) = table.tasks[index].trap_frame.as_mut() else {
        return false;
    };
    frame.set_entry(action.handler);
    frame.set_syscall_arg(0, signum);
    frame.set_syscall_arg(1, frame_addrs.siginfo);
    frame.set_syscall_arg(2, frame_addrs.ucontext);
    frame.set_user_sp(frame_addrs.frame_base);
    frame.set_user_return_address(restorer);
    frame.prepare_user_return();
    if interrupt_wait {
        if matches!(
            table.tasks[index].state,
            UserTaskState::Waiting | UserTaskState::Sleeping
        ) {
            table.interrupt_wait_for_signal(pid, signum);
        }
    }
    trace_signal_delivery_result(
        &table.tasks[index],
        signum,
        "delivered",
        interrupted_pc,
        interrupted_sp,
        frame_addrs.frame_base,
        restorer,
    );
    true
}

pub(in crate::syscall::process) fn queue_sigchld_for_parent(
    table: &mut UserProcessTable,
    parent_pid: usize,
) {
    let Some(index) = table.index_of(parent_pid) else {
        return;
    };
    if table.tasks[index].state == UserTaskState::Zombie {
        return;
    }
    let action = table.tasks[index].signal_actions.get(SIGCHLD);
    if action.handler == 0 || action.handler == super::SIG_IGN {
        return;
    }
    if table.tasks[index].signal_mask & signal_bit(SIGCHLD) != 0 {
        table.tasks[index].pending_sync_signal = Some(SIGCHLD);
        return;
    }
    queue_or_deliver_signal_handler_to_task(table, index, SIGCHLD);
}

pub fn deliver_current_sync_signal_handler(
    frame: &mut crate::arch::UserTrapFrame,
    signum: usize,
) -> bool {
    if signum == 0 || signum > MAX_SIGNAL {
        return false;
    }
    let mut table = USER_PROCESSES.lock();
    let Some(index) = table.current_index() else {
        return false;
    };
    if table.tasks[index].state != UserTaskState::Running {
        return false;
    }
    let action = table.tasks[index].signal_actions.get(signum);
    if action.handler == 0
        || action.handler == super::SIG_IGN
        || table.tasks[index].signal_mask & signal_bit(signum) != 0
    {
        return false;
    }

