#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub(in crate::syscall::process) struct KernelSigAction {
    pub(in crate::syscall::process) handler: usize,
    pub(in crate::syscall::process) flags: usize,
    pub(in crate::syscall::process) restorer: usize,
    pub(in crate::syscall::process) mask: u64,
}

#[derive(Clone)]
pub(in crate::syscall::process) struct SignalActions {
    inner: Arc<SpinLock<[KernelSigAction; MAX_SIGNAL + 1]>>,
}

impl SignalActions {
    pub(in crate::syscall::process) fn new() -> Self {
        Self {
            inner: Arc::new(SpinLock::new([KernelSigAction::default(); MAX_SIGNAL + 1])),
        }
    }

    pub(in crate::syscall::process) fn fork_copy(&self) -> Self {
        let actions = *self.inner.lock();
        Self {
            inner: Arc::new(SpinLock::new(actions)),
        }
    }

    pub(in crate::syscall::process) fn shared_clone(&self) -> Self {
        self.clone()
    }

    pub(in crate::syscall::process) fn get(&self, signum: usize) -> KernelSigAction {
        self.inner.lock()[signum]
    }

    pub(in crate::syscall::process) fn set(&self, signum: usize, action: KernelSigAction) {
        self.inner.lock()[signum] = action;
    }

    pub(in crate::syscall::process) fn reset_caught_for_exec(&self) {
        let mut actions = self.inner.lock();
        for signum in 1..=MAX_SIGNAL {
            let action = actions[signum];
            if action.handler != 0 && action.handler != SIG_IGN {
                actions[signum] = KernelSigAction::default();
            }
        }
    }
}

impl KernelSigAction {
    pub(in crate::syscall::process) const fn default() -> Self {
        Self {
            handler: 0,
            flags: 0,
            restorer: 0,
            mask: 0,
        }
    }
}

pub(super) fn signal_handler_mask(current: u64, signum: usize, action_mask: u64) -> u64 {
    let mut mask = current | action_mask | signal_bit(signum);
    mask &= !signal_bit(SIGKILL);
    mask &= !signal_bit(SIGSTOP);
    mask
}

pub(super) fn sanitized_signal_mask(mask: u64) -> u64 {
    mask & !signal_bit(SIGKILL) & !signal_bit(SIGSTOP)
}

pub(in crate::syscall::process) const fn signal_bit(signum: usize) -> u64 {
    if signum == 0 || signum > MAX_SIGNAL {
        0
    } else {
        1u64 << (signum - 1)
    }
}

