pub fn should_schedule_after_pipe_io(syscall_id: usize, fd: usize, ret: isize) -> bool {
    if ret < 0 || !super::super::table::has_other_runnable_user() {
        return false;
    }
    if !matches!(
        syscall_id,
        crate::syscall::number::SYS_READ
            | crate::syscall::number::SYS_READV
            | crate::syscall::number::SYS_WRITE
            | crate::syscall::number::SYS_WRITEV
            | crate::syscall::number::SYS_PREAD64
            | crate::syscall::number::SYS_PWRITE64
            | crate::syscall::number::SYS_PREADV
            | crate::syscall::number::SYS_PWRITEV
            | crate::syscall::number::SYS_SENDTO
            | crate::syscall::number::SYS_RECVFROM
            | crate::syscall::number::SYS_SHUTDOWN
    ) {
        return false;
    }
    let table = USER_PROCESSES.lock();
    let Some(index) = table.current_index() else {
        return false;
    };
    match table.tasks[index].fd_table.get(fd) {
        Ok(file) => match &*file {
            vfs::OpenFileKind::Pipe(_) => {
                matches!(
                    syscall_id,
                    crate::syscall::number::SYS_WRITE | crate::syscall::number::SYS_WRITEV
                ) && ret > 0
            }
            vfs::OpenFileKind::Inode(_) => ret > 0,
            vfs::OpenFileKind::Socket(socket) => match socket.kind() {
                Ok(SocketKind::Stream) => {
                    ret > 0
                        || matches!(
                            syscall_id,
                            crate::syscall::number::SYS_SENDTO
                                | crate::syscall::number::SYS_SHUTDOWN
                        )
                }
                Ok(SocketKind::Datagram) | Err(_) => false,
            },
            vfs::OpenFileKind::Console | vfs::OpenFileKind::Stdin => false,
        },
        Err(_) => false,
    }
}

