struct DevFileOps;

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum DevNode {
    Root,
    Null,
    Zero,
    Random,
    Urandom,
    Tty,
    Vda2,
    Misc,
    Rtc,
}

impl DevNode {
    fn inode(self) -> u32 {
        match self {
            DevNode::Root => 0,
            DevNode::Null => 1,
            DevNode::Zero => 2,
            DevNode::Random => 3,
            DevNode::Urandom => 4,
            DevNode::Tty => 5,
            DevNode::Vda2 => 6,
            DevNode::Misc => 7,
            DevNode::Rtc => RTC_INODE,
        }
    }
}

pub fn stat(inode: u32) -> Result<Metadata, isize> {
    Ok(metadata(node_from_inode(inode)?))
}

pub fn lookup_child(parent_inode: u32, name: &[u8]) -> Result<u32, isize> {
    let node = match node_from_inode(parent_inode)? {
        DevNode::Root => match name {
            b"null" => DevNode::Null,
            b"zero" => DevNode::Zero,
            b"random" => DevNode::Random,
            b"urandom" => DevNode::Urandom,
            b"tty" => DevNode::Tty,
            b"vda2" => DevNode::Vda2,
            b"misc" => DevNode::Misc,
            b"rtc" | b"rtc0" => DevNode::Rtc,
            _ => return Err(ENOENT),
        },
        DevNode::Misc => match name {
            b"rtc" => DevNode::Rtc,
            _ => return Err(ENOENT),
        },
        DevNode::Null
        | DevNode::Zero
        | DevNode::Random
        | DevNode::Urandom
        | DevNode::Tty
        | DevNode::Vda2
        | DevNode::Rtc => return Err(ENOTDIR),
    };
    Ok(node.inode())
}

pub fn read_at(inode: u32, _offset: u64, out: &mut [u8]) -> Result<usize, isize> {
    match node_from_inode(inode)? {
        DevNode::Null | DevNode::Tty | DevNode::Vda2 | DevNode::Rtc => Ok(0),
        DevNode::Zero => {
            out.fill(0);
            Ok(out.len())
        }
        DevNode::Random | DevNode::Urandom => {
            fill_pseudorandom(out, inode as u64 ^ _offset);
            Ok(out.len())
        }
        DevNode::Root | DevNode::Misc => Err(EINVAL),
    }
}

pub fn write_at(inode: u32, _offset: u64, input: &[u8]) -> Result<usize, isize> {
    match node_from_inode(inode)? {
        DevNode::Null
        | DevNode::Zero
        | DevNode::Random
        | DevNode::Urandom
        | DevNode::Vda2
        | DevNode::Rtc => Ok(input.len()),
        DevNode::Tty => {
            console::write_bytes(input);
            Ok(input.len())
        }
        DevNode::Root | DevNode::Misc => Err(EINVAL),
    }
}

pub fn ioctl(inode: u32, request: u32, out: &mut [u8]) -> Result<usize, isize> {
    match (node_from_inode(inode)?, request) {
        (DevNode::Rtc, RTC_RD_TIME) => {
            if out.len() < RTC_TIME_SIZE {
                return Err(EINVAL);
            }
            out[..RTC_TIME_SIZE].copy_from_slice(&rtc_time_bytes());
            Ok(RTC_TIME_SIZE)
        }
        (DevNode::Vda2, BLKGETSIZE64) => {
            if out.len() < 8 {
                return Err(EINVAL);
            }
            out[..8].copy_from_slice(&VDA2_SIZE_BYTES.to_ne_bytes());
            Ok(8)
        }
        _ => Err(ENOTTY),
    }
}

pub fn file_ops() -> Arc<dyn FileOps> {
    Arc::new(DevFileOps)
}

impl FileOps for DevFileOps {
    fn name(&self) -> &'static str {
        "devfs"
    }

    fn read(&self, file: &mut OpenFile, out: &mut [u8]) -> Result<usize, isize> {
        if file.file_type != FileType::Regular {
            return Err(EINVAL);
        }
        if !file.can_read() {
            return Err(EBADF);
        }
        let read = read_at(file.inode.raw(), file.offset, out)?;
        file.offset = file.offset.checked_add(read as u64).ok_or(EINVAL)?;
        Ok(read)
    }

    fn write(&self, file: &mut OpenFile, input: &[u8], _status_flags: i32) -> Result<usize, isize> {
        if !file.can_write() {
            return Err(EBADF);
        }
        let written = write_at(file.inode.raw(), file.offset, input)?;
        file.offset = file.offset.checked_add(written as u64).ok_or(EINVAL)?;
        Ok(written)
    }

    fn getdents(&self, _file: &mut OpenFile, _out: &mut [u8]) -> Result<usize, isize> {
        Err(EINVAL)
    }

    fn stat(&self, file: &OpenFile) -> Result<Metadata, isize> {
        stat(file.inode.raw())
    }

    fn seek(&self, file: &mut OpenFile, offset: isize, whence: SeekWhence) -> Result<u64, isize> {
        if file.file_type != FileType::Regular {
            return Err(ESPIPE);
        }
        let base = match whence {
            SeekWhence::Set => 0i128,
            SeekWhence::Current => file.offset as i128,
            SeekWhence::End => self.stat(file)?.size as i128,
        };
        let next = base.checked_add(offset as i128).ok_or(EINVAL)?;
        if next < 0 || next > u64::MAX as i128 {
            return Err(EINVAL);
        }
        file.offset = next as u64;
        Ok(file.offset)
    }

    fn ioctl(&self, file: &mut OpenFile, request: u32, out: &mut [u8]) -> Result<usize, isize> {
        ioctl(file.inode.raw(), request, out)
    }

    fn poll_revents(&self, file: &OpenFile, events: i16) -> i16 {
        let mut revents = 0;
        if events & crate::fs::vfs::POLLIN != 0 && file.can_read() {
            revents |= crate::fs::vfs::POLLIN;
        }
        if events & crate::fs::vfs::POLLOUT != 0 && file.can_write() {
            revents |= crate::fs::vfs::POLLOUT;
        }
        revents
    }
}

fn node_from_inode(inode: u32) -> Result<DevNode, isize> {
    match inode {
        0 => Ok(DevNode::Root),
        1 => Ok(DevNode::Null),
        2 => Ok(DevNode::Zero),
        3 => Ok(DevNode::Random),
        4 => Ok(DevNode::Urandom),
        5 => Ok(DevNode::Tty),
        6 => Ok(DevNode::Vda2),
        7 => Ok(DevNode::Misc),
        RTC_INODE => Ok(DevNode::Rtc),
        _ => Err(ENOENT),
    }
}

fn metadata(node: DevNode) -> Metadata {
    let file_type = if matches!(node, DevNode::Root | DevNode::Misc) {
        FileType::Directory
    } else {
        FileType::Regular
    };
    Metadata {
        inode: NodeId::devfs(node.inode()),
        mode: match node {
            DevNode::Root | DevNode::Misc => 0o040755,
            DevNode::Vda2 => 0o060666,
            DevNode::Null
            | DevNode::Zero
            | DevNode::Random
            | DevNode::Urandom
            | DevNode::Tty
            | DevNode::Rtc => 0o020666,
        },
        file_type,
        nlink: if file_type == FileType::Directory {
            2
        } else {
            1
        },
        uid: 0,
        gid: 0,
        rdev: rdev_for_node(node),
        size: 0,
        times: FileTimes::ZERO,
        flags: 0,
    }
}

const fn rdev_for_node(node: DevNode) -> DeviceId {
    match node {
        DevNode::Null => DeviceId { major: 1, minor: 3 },
        DevNode::Zero => DeviceId { major: 1, minor: 5 },
        DevNode::Random => DeviceId { major: 1, minor: 8 },
        DevNode::Urandom => DeviceId { major: 1, minor: 9 },
        DevNode::Tty => DeviceId { major: 5, minor: 0 },
        DevNode::Vda2 => DeviceId {
            major: 254,
            minor: 2,
        },
        DevNode::Rtc => DeviceId {
            major: 10,
            minor: 135,
        },
        DevNode::Root | DevNode::Misc => DeviceId::ZERO,
    }
}

