pub fn sys_socket(domain: usize, raw_type: usize, protocol: usize) -> SyscallRet {
    let Some(result) = process::with_current_user_mut_and_sync_fds(|task| {
        let raw_type = raw_type as i32;
        let kind = match raw_type & SOCK_TYPE_MASK {
            SOCK_STREAM => socket::SocketKind::Stream,
            SOCK_DGRAM => socket::SocketKind::Datagram,
            _ => return Err(EPROTOTYPE),
        };
        let flags = raw_type & (SOCK_CLOEXEC | SOCK_NONBLOCK);
        if raw_type & !(SOCK_TYPE_MASK | SOCK_CLOEXEC | SOCK_NONBLOCK) != 0 {
            return Err(EINVAL);
        }
        let endpoint = socket::create(domain as i32, kind, protocol as i32)?;
        let limit = process::nofile_limit(task);
        task.fd_table
            .insert_socket_limited(endpoint, flags, limit)
            .map(|fd| fd as isize)
    }) else {
        return err(EPERM);
    };
    result.unwrap_or_else(err)
}

