pub fn sys_writev(fd: usize, iov_addr: usize, iovcnt: usize) -> SyscallRet {
    if iovcnt == 0 {
        return 0;
    }
    if iovcnt > MAX_IOVEC_COUNT {
        return err(EINVAL);
    }
