        // 对单段 (ssize_t)iov_len < 0 或累加长度溢出 ssize_t 返回 EINVAL(LTP writev01)。
        let mut checked_total = 0usize;
        for index in 0..iovcnt {
            let entry_addr = iov_addr.checked_add(index * 16).ok_or(EFAULT)?;
            let mut raw = [0u8; 16];
            UserBuffer::new(entry_addr, raw.len())
                .read(current.task().memory.page_table(), &mut raw)
                .map_err(|_| EFAULT)?;
            let len = usize::from_ne_bytes(raw[8..16].try_into().unwrap());
            if len > isize::MAX as usize {
                return Err(EINVAL);
            }
            checked_total = checked_total
                .checked_add(len)
                .filter(|sum| *sum <= isize::MAX as usize)
                .ok_or(EINVAL)?;
        }
        let mut total = 0usize;
        for index in 0..iovcnt {
            let entry_addr = iov_addr.checked_add(index * 16).ok_or(EFAULT)?;
            let mut raw = [0u8; 16];
            UserBuffer::new(entry_addr, raw.len())
                .read(current.task().memory.page_table(), &mut raw)
                .map_err(|_| EFAULT)?;
            let base = usize::from_ne_bytes(raw[0..8].try_into().unwrap());
            let len = usize::from_ne_bytes(raw[8..16].try_into().unwrap());
            let mut done = 0usize;
            let mut chunk = [0u8; USER_IO_CHUNK_SIZE];
            while done < len {
                let chunk_len = core::cmp::min(chunk.len(), len - done);
                let addr = base.checked_add(done).ok_or(EFAULT)?;
                UserBuffer::new(addr, chunk_len)
                    .read(current.task().memory.page_table(), &mut chunk[..chunk_len])
                    .map_err(|_| EFAULT)?;
                let step = write_kernel_bytes(current, fd, &chunk[..chunk_len])?;
                if step == process::SYSCALL_BLOCKED {
                    return Ok(if total == 0 {
                        process::SYSCALL_BLOCKED
                    } else {
                        total as isize
                    });

