        if key != IPC_PRIVATE {
            if let Some(segment) = self.segments.iter().find(|segment| segment.key == key) {
                if shmflg & IPC_CREAT != 0 && shmflg & IPC_EXCL != 0 {
                    return Err(EEXIST);
                }
                if size > segment.size {
                    return Err(EINVAL);
                }
                return Ok(segment.id);
            }
            if shmflg & IPC_CREAT == 0 {
                return Err(ENOENT);
            }
        }
        self.create_segment(key, size)
    }

    fn create_segment(&mut self, key: usize, size: usize) -> Result<usize, isize> {
