const FUTEX_CMD_MASK: usize = 0x7f;
const FUTEX_WAIT: usize = 0;
const FUTEX_WAKE: usize = 1;
const FUTEX_REQUEUE: usize = 3;
const FUTEX_WAIT_BITSET: usize = 9;
const FUTEX_WAKE_BITSET: usize = 10;
const MEMBARRIER_CMD_QUERY: usize = 0;
const MEMBARRIER_CMD_PRIVATE_EXPEDITED: usize = 1 << 3;
const MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED: usize = 1 << 4;
const MEMBARRIER_SUPPORTED_CMDS: usize =
    MEMBARRIER_CMD_PRIVATE_EXPEDITED | MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED;

#[derive(Clone, Copy)]
enum FutexTimeoutMode {
    Relative,
    Absolute,
}
pub fn sys_futex(
    uaddr: usize,
    op: usize,
    value: usize,
    value2: usize,
    uaddr2: usize,
    _value3: usize,
) -> SyscallRet {
    let command = op & FUTEX_CMD_MASK;
    match command {
        FUTEX_WAIT => sys_futex_wait(uaddr, value, value2, FutexTimeoutMode::Relative),
        FUTEX_WAKE => sys_futex_wake(uaddr, value),
        FUTEX_REQUEUE => sys_futex_requeue(uaddr, value, value2, uaddr2),
        FUTEX_WAIT_BITSET => {
            if _value3 == 0 {
                return err(EINVAL);
            }
            sys_futex_wait(uaddr, value, value2, FutexTimeoutMode::Absolute)
        }
        FUTEX_WAKE_BITSET => {
            if _value3 == 0 {
                return err(EINVAL);
            }
            sys_futex_wake(uaddr, value)
        }
        _ => err(EINVAL),
    }
}

pub fn sys_membarrier(command: usize, flags: usize) -> SyscallRet {
    if flags != 0 {
        return err(EINVAL);
    }
    match command {
        MEMBARRIER_CMD_QUERY => MEMBARRIER_SUPPORTED_CMDS as isize,
        MEMBARRIER_CMD_REGISTER_PRIVATE_EXPEDITED => 0,
        MEMBARRIER_CMD_PRIVATE_EXPEDITED => {
            fence(Ordering::SeqCst);
            0
        }
        _ => err(EINVAL),
    }
}

fn sys_futex_wait(
    uaddr: usize,
    value: usize,
    timeout_addr: usize,
    timeout_mode: FutexTimeoutMode,
) -> SyscallRet {
    let mut table = USER_PROCESSES.lock();
    let Some(index) = table.current_index() else {
        return err(EPERM);
    };
    if table.tasks[index].state != UserTaskState::Running {
        return err(EPERM);
    }
    let current_pid = table.tasks[index].pid;
    if table.take_signal_wake(current_pid).is_some()
        || table.take_wake_reason(current_pid, WakeReason::SignalPending)
    {
        return err(EINTR);
    }
    if table.take_wake_reason(current_pid, WakeReason::FutexWake) {
        return 0;
    }
    if table.take_wake_reason(current_pid, WakeReason::Timeout) {
        return err(ETIMEDOUT);
    }

    let mut raw = [0u8; core::mem::size_of::<u32>()];
    if UserBuffer::new(uaddr, raw.len())
        .read(table.tasks[index].memory.page_table(), &mut raw)
        .is_err()
    {
        return err(EFAULT);
    }
    trace_musl_thread_lock_state(
        "wait",
        current_pid,
        uaddr,
        op_value(value),
        table.tasks[index].memory.page_table(),
    );
    trace_la_shared_words_locked("futex-wait", &table, uaddr);
    if u32::from_ne_bytes(raw) != value as u32 {
        return err(EAGAIN);
    }
    let deadline = match futex_deadline_micros(&table.tasks[index], timeout_addr, timeout_mode) {
        Ok(deadline) => deadline,
        Err(errno) => return err(errno),
    };
    if let Some(deadline) = deadline {
        if deadline <= crate::arch::uptime_micros() {
            return err(ETIMEDOUT);
        }
        if !table.wait_current_for_futex_until(uaddr, deadline) {
            return err(EPERM);
        }
    } else if !table.wait_current_for_futex(uaddr) {
        return err(EPERM);
    }
    SYSCALL_BLOCKED
}

