#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct KernelItimerval {
    interval_micros: u64,
    value_micros: u64,
}

pub fn sys_setitimer(which: usize, new_value_addr: usize, old_value_addr: usize) -> SyscallRet {
    if !is_supported_itimer(which) {
        return err(EINVAL);
    }

    let mut table = USER_PROCESSES.lock();
    let Some(index) = table.current_index() else {
        return err(EPERM);
    };
    if table.tasks[index].state != UserTaskState::Running {
        return err(EPERM);
    }
    let now = crate::arch::uptime_micros();
    if old_value_addr != 0 {
        let old = current_itimer(&table.tasks[index], which, now);
        if write_itimerval(&table.tasks[index], old_value_addr, old).is_err() {
            return err(EFAULT);
        }
    }
    if new_value_addr == 0 {
        return err(EFAULT);
    }
    let next = match read_itimerval(&table.tasks[index], new_value_addr) {
        Ok(value) => value,
        Err(errno) => return err(errno),
    };
    set_itimer(&mut table, index, which, now, next);
    0
}

/// getitimer(2): 读取当前 itimer 值。
pub fn sys_getitimer(which: usize, value_addr: usize) -> SyscallRet {
    if value_addr == 0 {
        return err(EFAULT);
    }
    let table = USER_PROCESSES.lock();
    let Some(index) = table.current_index() else {
        return err(EPERM);
    };
    if table.tasks[index].state != UserTaskState::Running {
        return err(EPERM);
    }
    // 先探测 value_addr 可写性（EFAULT 优先于 EINVAL，LTP getitimer02）
    if write_itimerval(
        &table.tasks[index],
        value_addr,
        KernelItimerval {
            interval_micros: 0,
            value_micros: 0,
        },
    )
    .is_err()
    {
        return err(EFAULT);
    }
    if !is_supported_itimer(which) {
        return err(EINVAL);
    }
    let now = crate::arch::uptime_micros();
    let current = current_itimer(&table.tasks[index], which, now);
    if write_itimerval(&table.tasks[index], value_addr, current).is_err() {
        return err(EFAULT);
    }
    0
}

